#[no_mangle]
pub fn fake_meow(hart_id: usize) {
    unsafe {
        asm!("add sp, sp, {}", in(reg) KERNEL_DIRECT_OFFSET << PAGE_SIZE_BITS);
        asm!("la t0, meow");
        asm!("add t0, t0, {}", in(reg) KERNEL_DIRECT_OFFSET << PAGE_SIZE_BITS);
        asm!("mv a0, {}", in(reg) hart_id);
        asm!("jalr zero, 0(t0)");
    }
}

static FIRST_HART: AtomicBool = AtomicBool::new(true);

#[cfg(not(feature = "multi-harts"))]
#[no_mangle]
pub fn meow(hart_id: usize) -> ! {
    if FIRST_HART
        .compare_exchange(true, false, Ordering::SeqCst, Ordering::SeqCst)
        .is_ok()
    {
        init_bss();
        logging::init();
        hart::init(hart_id);
        unsafe { set_fs(FS::Dirty) }
        mm::init();
        trap::init();
        executor::init();
        fs::init();
        timer::init();
        // spawn_kernel_thread(async move {
        //     process::add_initproc();
        // });
        process::init();
        trap::enable_stimer_interrupt();
        timer::set_next_trigger();
        loop {
            executor::run_until_idle();
        }
        #[cfg(feature = "time-tracer")]
        time_trace_show!();
    } else {
        loop {}
    }
}

#[cfg(feature = "multi-harts")]
#[no_mangle]
pub fn meow() -> ! {
    if hartid!() == 0 {
        init_bss();
        unsafe { set_fs(FS::Dirty) }
        lang_items::setup();
        mm::init_frame_allocator();
        mm::enable_mmu();
        trap::init();
        trap::enable_stimer_interrupt();
        timer::set_next_trigger();
        fs::init();
        process::add_initproc();

        synchronize_hart!()
    } else {
        wait_for_booting!();

        unsafe { set_fs(FS::Dirty) }

        mm::enable_mmu();
        trap::init();
        trap::enable_stimer_interrupt();
        timer::set_next_trigger();
    }

    process::run_tasks();
    unreachable!();
}

fn init_bss() {
    extern "C" {
        fn ekstack0();
        fn ebss();
    }
    unsafe {
        let sbss = ekstack0 as usize as *mut u8;
        let ebss = ebss as usize as *mut u8;
        slice::from_mut_ptr_range(sbss..ebss)
            .iter_mut()
            .for_each(|byte| (byte as *mut u8).write_volatile(0));
    }
}

