/// 物理页帧，代表 RAM 上一段实际的物理页，通过物理页号标识
pub struct FrameTracker {
    pub ppn: PhysPageNum,
}

impl FrameTracker {
    /// 通过物理页号创建一个物理页帧的结构体，创建时初始化内存空间
    pub fn new(ppn: PhysPageNum) -> Self {
        let bytes_arr = ppn.as_bytes_array();
        bytes_arr.iter_mut().for_each(|b| *b = 0);

        frame_add_ref(ppn);

        Self { ppn }
    }

    pub fn from_ppn(ppn: PhysPageNum) -> Self {
        frame_add_ref(ppn);
        Self { ppn }
    }
}

impl Debug for FrameTracker {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("FrameTracker:PPN={:#x}", self.ppn.0))
    }
}

impl Drop for FrameTracker {
    fn drop(&mut self) {
        dealloc_frame(self.ppn);
    }
}

/// 物理页帧管理器
trait FrameAllocator {
    /// 新建一个实例，在使用前需要初始化
    fn new() -> Self;
    /// 从空闲物理页中分配一个物理页
    fn alloc(&mut self) -> Option<PhysPageNum>;
    /// 回收物理页
    fn dealloc(&mut self, ppn: PhysPageNum);

    fn add_ref(&mut self, ppn: PhysPageNum);

    fn enquire_ref(&self, ppn: PhysPageNum) -> usize;

    fn usage(&self) -> (usize, usize, usize, usize);
}

/// 栈式物理页帧管理器
pub struct StackFrameAllocator {
    /// 管理内存的起始物理页号
    base_num: usize,
    /// 管理内存的结束物理页号
    end: usize,
    /// 空闲内存的起始物理页号
    current: usize,
    /// 以后入先出的方式保存被回收的物理页号
    recycled: Vec<usize>,
    /// 引用计数器
    refcounter: BTreeMap<usize, u8>,
}

impl StackFrameAllocator {
    /// 初始化栈式物理页管理器
    /// - `l`:空闲内存起始页号
    /// - `r`:空闲内存结束页号
    pub fn init(&mut self, l: PhysPageNum, r: PhysPageNum) {
        self.current = l.0;
        self.end = r.0;
        self.base_num = l.0;
    }
}
impl FrameAllocator for StackFrameAllocator {
    fn new() -> Self {
        Self {
            base_num: 0,
            current: 0,
            end: 0,
            recycled: Vec::new(),
            refcounter: BTreeMap::new(),
        }
    }
    fn alloc(&mut self) -> Option<PhysPageNum> {
        // 首先检查栈 recycled 内有没有之前回收的物理页号，如果有的话直接弹出栈顶并返回
        if let Some(ppn) = self.recycled.pop() {
            self.refcounter.insert(ppn, 0);
            Some(ppn.into())
        }
        // 空间满返回 None
        else if self.current == self.end {
            None
        }
        // 否则就返回最低的物理页号
        else {
            self.current += 1;
            self.refcounter.insert(self.current - 1, 0);
            Some((self.current - 1).into())
        }
    }
    fn dealloc(&mut self, ppn: PhysPageNum) {
        let ppn = ppn.0;
        let ref_times = self.refcounter.get_mut(&ppn).unwrap();
        assert!(
            *ref_times > 0,
            "[StackFrameAllocator::dealloc] Frame ppn={:#x} has no reference!",
            ppn
        );
        *ref_times -= 1;
        if *ref_times == 0 {
            self.refcounter.remove(&ppn);
            // 验证物理页号有效性，PPN大于已分配的最高内存或已释放栈中存在这个物理页号
            if ppn >= self.current || self.recycled.iter().any(|&v| v == ppn) {
                panic!(
                    "[StackFrameAllocator::dealloc] Frame ppn={:#x} has not been allocated!",
                    ppn
                );
            }
            // 回收，压栈
            self.recycled.push(ppn);
        }
    }
    fn usage(&self) -> (usize, usize, usize, usize) {
        (self.current, self.recycled.len(), self.end, self.base_num)
    }
    fn add_ref(&mut self, ppn: PhysPageNum) {
        let ppn = ppn.0;
        let ref_times = self.refcounter.get_mut(&ppn).unwrap();
        *ref_times += 1;
    }
    fn enquire_ref(&self, ppn: PhysPageNum) -> usize {
        let ppn = ppn.0;
        let ref_times = self.refcounter.get(&ppn).unwrap();
        (*ref_times) as usize
    }
}

/// 物理页帧管理器实例类型
type FrameAllocatorImpl = StackFrameAllocator;

lazy_static! {
    /// 物理页帧管理器实例
    /// - 全局变量，管理除内核空间外的内存空间
    pub static ref FRAME_ALLOCATOR: Mutex<FrameAllocatorImpl> =
        Mutex::new(FrameAllocatorImpl::new());
}

/// 初始化物理页帧管理器
/// - 物理页帧范围
///     - 对 `ekernel` 物理地址上取整获得起始物理页号
///     - 对 `PHYS_END` 物理地址下取整获得结束物理页号
pub fn init() {
    extern "C" {
        fn ekernel();
    }
    FRAME_ALLOCATOR.lock().init(
        PhysAddr::from(KernAddr::from(ekernel as usize)).ceil(),
        PhysAddr::from(KernAddr::from(VIRT_END)).floor(),
    );
    debug!(
        "frame allocator init finshed, start {:#x}, end {:#x}",
        ekernel as usize, VIRT_END
    );
}

/// 分配物理页帧
pub fn alloc_frame() -> Option<FrameTracker> {
    let ppn = FRAME_ALLOCATOR.lock().alloc()?;
    Some(FrameTracker::new(ppn))
}

/// 回收物理页帧
pub fn dealloc_frame(ppn: PhysPageNum) {
    FRAME_ALLOCATOR.lock().dealloc(ppn);
}

pub fn frame_add_ref(ppn: PhysPageNum) {
    FRAME_ALLOCATOR.lock().add_ref(ppn)
}

pub fn enquire_refcount(ppn: PhysPageNum) -> usize {
    FRAME_ALLOCATOR.lock().enquire_ref(ppn)
}

//! The global allocator
use core::{
    alloc::{GlobalAlloc, Layout},
    ptr::NonNull,
};

use crate::{consts::KERNEL_HEAP_SIZE, sync::mutex::SpinNoIrqLock};
use buddy_system_allocator::Heap;
use log::{debug, error};

#[global_allocator]
static HEAP_ALLOCATOR: GlobalHeap = GlobalHeap::empty();

#[alloc_error_handler]
/// When heap allocation error occurs, the control flow will come here
pub fn handle_alloc_error(layout: core::alloc::Layout) -> ! {
    error!("heap alloc err!!");
    panic!("Heap allocation error, layout = {:#x?}", layout);
}

struct GlobalHeap(SpinNoIrqLock<Heap<32>>);

impl GlobalHeap {
    const fn empty() -> Self {
        Self(SpinNoIrqLock::new(Heap::empty()))
    }
}

unsafe impl GlobalAlloc for GlobalHeap {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        self.0
            .lock()
            .alloc(layout)
            .ok()
            .map_or(core::ptr::null_mut::<u8>(), |allocation| {
                allocation.as_ptr()
            })
    }

    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        self.0.lock().dealloc(NonNull::new_unchecked(ptr), layout)
    }
}

/// heap space ([u8; KERNEL_HEAP_SIZE])
static mut HEAP_SPACE: [u8; KERNEL_HEAP_SIZE] = [0; KERNEL_HEAP_SIZE];

pub fn init_heap() {
    unsafe {
        let start = HEAP_SPACE.as_ptr() as usize;
        HEAP_ALLOCATOR.0.lock().init(start, KERNEL_HEAP_SIZE);
        debug!(
            "[kernel] heap start {:#x}, end {:#x}",
            start,
            start + KERNEL_HEAP_SIZE
        );
    }
}

///
#[allow(unused)]
pub fn heap_test() {
    debug!("heap_test start...");
    use alloc::boxed::Box;
    use alloc::vec::Vec;
    extern "C" {
        fn sbss();
        fn ebss();
    }
    let bss_range = sbss as usize..ebss as usize;
    let a = Box::new(5);
    assert_eq!(*a, 5);
    assert!(bss_range.contains(&(a.as_ref() as *const _ as usize)));
    drop(a);
    let mut v: Vec<usize> = Vec::new();
    let max_len = (KERNEL_HEAP_SIZE - 10000) / core::mem::size_of::<usize>();
    for i in 0..500 {
        v.push(i);
    }
    for (i, val) in v.iter().take(500).enumerate() {
        assert_eq!(*val, i);
    }
    assert!(bss_range.contains(&(v.as_ptr() as usize)));
    drop(v);
    debug!("heap_test passed!");
}

//! Sv39 页表
//!
//!
//! ```text
//!                    +--------+--------+--------+
//!  stap      offset: | VPN[2] | VPN[1] | VPN[0] |
//!    |               +--------+--------+--------+
//!    |                    |
//!    +--> +--------+      |
//!         |        |      |
//!         +--------+ <----+
//!         |  PTE   | -------> +--------+      +----------+
//!         +--------+          |        |      |          |
//!         |        |          +--------+      +----------+      +------------+
//!         +--------+          |        |  ··· | leaf PTE | ---> |FrameTracker|
//!         |        |          +--------+      +----------+      +------------+
//!         +--------+          |        |      |          |
//!            物理页            +--------+      +----------+
//!                             |        |      |          |
//!                             +--------+      +----------+
//! ```

use core::arch::asm;

use crate::consts::KERNEL_DIRECT_OFFSET;

use super::address::{PhysAddr, PhysPageNum, VirtAddr, VirtPageNum};
use super::kernel_vmm::acquire_kvmm;
use super::{alloc_frame, FrameTracker};
use alloc::vec;
use alloc::vec::Vec;
use bitflags::*;
use riscv::register::satp;

// SV39 多级页表
#[derive(Debug)]
pub struct PageTable {
    /// 根节点的物理页号,作为页表唯一的区分标志
    root_ppn: PhysPageNum,
    /// 以 FrameTracker 的形式保存了页表所有的节点（包括根节点）所在的物理页帧
    /// 用以延长物理页帧的生命周期
    frames: Vec<FrameTracker>,
}

impl PageTable {
    /// 新建一个 `PageTable`
    pub fn new() -> Self {
        let frame = alloc_frame().unwrap();
        PageTable {
            root_ppn: frame.ppn,
            frames: vec![frame], // 将新获取到的物理页帧存入向量
        }
    }

    /// 单页表设计需要保证内核空间映射关系的一致性问题
    pub fn with_kern_mapping() -> Self {
        let frames = alloc_frame().unwrap();
        let global_root_ppn = unsafe { (*acquire_kvmm().page_table.get()).root_ppn };

        let foo_1 = VirtPageNum::from(0x0008_0000).indexes()[0];
        let foo_2 = VirtPageNum::from(0x0008_8000).indexes()[0];
        frames.ppn.as_pte_array()[foo_1..=foo_2]
            .copy_from_slice(&global_root_ppn.as_pte_array()[foo_1..=foo_2]);

        let first_level_index = VirtPageNum::from(KERNEL_DIRECT_OFFSET).indexes()[0];
        frames.ppn.as_pte_array()[first_level_index..]
            .copy_from_slice(&global_root_ppn.as_pte_array()[first_level_index..]);

        PageTable {
            root_ppn: frames.ppn,
            frames: vec![frames],
        }
    }

    /// 通过 `satp` 获取对应的多级页表
    ///
    /// `satp` 寄存器在 x64 上的布局：
    /// ```text
    ///    64     60             44                   0
    ///     +------+--------------+-------------------+
    ///     | MODE |     ASID     |        PPN        |
    ///     +------+--------------+-------------------+
    ///         4         16                44
    /// ```
    ///
    /// **hint**: 物理页号位宽 44 bits
    pub fn from_token(satp: usize) -> Self {
        Self {
            // 取satp的前44位作为物理页号
            root_ppn: PhysPageNum::from(satp & ((1usize << 44) - 1)),
            // 不需要重新生成节点，节点已经在原始多级页表中存在，同时存在在内存中
            frames: Vec::new(),
        }
    }

    /// 根据vpn查找对应页表项，如果在查找过程中发现无效页表则新建页表
    fn find_pte_create(&mut self, vpn: VirtPageNum) -> Option<&mut PageTableEntry> {
        let idxs = vpn.indexes();
        // 当前节点的物理页号，最开始指向多级页表的根节点
        let mut ppn = self.root_ppn;
        let mut result: Option<&mut PageTableEntry> = None;
        for (i, idx) in idxs.iter().enumerate() {
            // 通过 get_pte_array 将取出当前节点的页表项数组，并根据当前级页索引找到对应的页表项
            let pte = &mut ppn.as_pte_array()[*idx];
            if i == 2 {
                // 找到第三级页表，这个页表项的可变引用
                result = Some(pte);
                break;
            }
            if !pte.is_valid() {
                // 发现页表项是无效的状态
                // 获取一个物理页帧
                let frame = alloc_frame().unwrap();
                // 用获取到的物理页帧生成新的页表项
                *pte = PageTableEntry::new(frame.ppn, PTEFlags::V);
                // 将生成的页表项存入页表
                self.frames.push(frame);
            }
            // 切换到下一级页表（物理页帧）
            ppn = pte.ppn();
        }
        result
    }

    /// 根据vpn查找对应页表项，如果在查找过程中发现无效页表则直接返回 None 即查找失败
    pub fn find_pte(&self, vpn: VirtPageNum) -> Option<&mut PageTableEntry> {
        let idxs = vpn.indexes();
        let mut ppn = self.root_ppn;
        let mut result: Option<&mut PageTableEntry> = None;
        for (i, idx) in idxs.iter().enumerate() {
            let pte = &mut ppn.as_pte_array()[*idx];
            if !pte.is_valid() {
                return None;
            }
            if i == 2 {
                result = Some(pte);
                break;
            }
            ppn = pte.ppn();
        }
        result
    }

    /// 建立一个虚拟页号到物理页号的映射
    ///
    /// 根据VPN找到第三级页表中的对应项，将 `PPN` 和 `flags` 写入到页表项
    pub fn map(&mut self, vpn: VirtPageNum, ppn: PhysPageNum, flags: PTEFlags) {
        let pte = self.find_pte_create(vpn).unwrap();
        // 断言，保证新获取到的PTE是无效的（不是已分配的）
        assert!(!pte.is_valid(), "{:?} is mapped before mapping", vpn);
        *pte = PageTableEntry::new(ppn, flags | PTEFlags::V);
    }

    /// 删除一个虚拟页号到物理页号的映射
    ///
    /// 只需根据虚拟页号找到页表项，然后修改或者直接清空其内容即可
    pub fn unmap(&mut self, vpn: VirtPageNum) {
        let pte = self.find_pte(vpn).unwrap();
        assert!(pte.is_valid(), "{:?} is invalid before unmapping", vpn);
        pte.clear();
    }

    /// 根据 vpn 查找页表项
    ///
    /// 调用 `find_pte` 来实现，如果能够找到页表项，那么它会将页表项拷贝一份并返回，否则就返回一个 `None`
    pub fn translate(&self, vpn: VirtPageNum) -> Option<PageTableEntry> {
        self.find_pte(vpn).map(|pte| *pte)
    }

    /// 在当前多级页表中将虚拟地址转换为物理地址
    pub fn translate_va(&self, va: VirtAddr) -> Option<PhysAddr> {
        self.find_pte(va.clone().floor()).map(|pte| {
            //println!("translate_va:va = {:?}", va);
            let aligned_pa: PhysAddr = pte.ppn().into();
            //println!("translate_va:pa_align = {:?}", aligned_pa);
            let offset = va.page_offset();
            let aligned_pa_usize: usize = aligned_pa.into();

            (aligned_pa_usize + offset).into()
        })
    }

    pub fn activate(&self) {
        let satp = self.token();
        unsafe {
            satp::write(satp);
            asm!("sfence.vma");
        }
    }

    /// 按照 satp CSR 格式要求 构造一个无符号 64 位无符号整数，使得其分页模式为 SV39 ，且将当前多级页表的根节点所在的物理页号填充进去
    pub fn token(&self) -> usize {
        8usize << 60 | self.root_ppn.0
    }

    pub fn set_cow(&mut self, vpn: VirtPageNum) {
        self.find_pte_create(vpn).unwrap().set_cow();
    }

    pub fn reset_cow(&mut self, vpn: VirtPageNum) {
        self.find_pte_create(vpn).unwrap().reset_cow();
    }

    pub fn set_flags(&mut self, vpn: VirtPageNum, flags: PTEFlags) {
        self.find_pte_create(vpn).unwrap().set_flags(flags);
    }

    pub fn remap_cow(&mut self, vpn: VirtPageNum, ppn: PhysPageNum, former_ppn: PhysPageNum) {
        let pte = self.find_pte_create(vpn).unwrap();
        *pte = PageTableEntry::new(ppn, pte.flags() | PTEFlags::W);
        ppn.as_bytes_array()
            .copy_from_slice(former_ppn.as_bytes_array());
    }
}

// 可以将一个 u8 封装成一个标志位的集合类型，支持一些常见的集合运算
bitflags! {
    /// PTEFlags 一共 10 bits
    #[derive(Clone, Copy)]
    pub struct PTEFlags: u16 {
        /// 如果该位置零，则当前 [`PTE`] 的其他位将失去其应有的意义，具体意义由软件决定
        ///
        /// 换言之，如果 MMU 转换过程中遇到 `!contains(PTEFlags::V)` 的情况，则会引发 Page Fault
        ///
        /// [`PTE`]: PageTableEntry
        const V = 1 << 0;

        const R = 1 << 1;
        const W = 1 << 2;
        /// 该 [`PTE`] 指向的物理页是否可执行
        ///
        /// [`PTE`]: PageTableEntry
        const X = 1 << 3;

        /// 该 [`PTE`] 指向的物理页在用户态是否可以访问
        ///
        /// [`PTE`]: PageTableEntry
        const U = 1 << 4;

        const G = 1 << 5;
        const A = 1 << 6;
        const D = 1 << 7;

        /// 页表项指向的物理页帧是否需要写时复制
        const COW = 1 << 8;
    }
}

