impl VirtAddr {
    /// 从虚拟地址计算虚拟页号（下取整）
    pub fn floor(&self) -> VirtPageNum {
        VirtPageNum(self.0 / PAGE_SIZE)
    }
    /// 从虚拟地址计算虚拟页号（下取整）
    pub fn ceil(&self) -> VirtPageNum {
        VirtPageNum((self.0 + PAGE_SIZE - 1) / PAGE_SIZE)
    }
    /// 从虚拟地址获取页内偏移（物理地址的低12位）
    pub fn page_offset(&self) -> usize {
        self.0 & (PAGE_SIZE - 1)
    }
    /// 判断虚拟地址是否与页面大小对齐
    pub fn is_aligned(&self) -> bool {
        self.page_offset() == 0
    }
}

impl PhysAddr {
    /// 从物理地址计算物理页号（下取整）
    pub fn floor(&self) -> PhysPageNum {
        PhysPageNum(self.0 / PAGE_SIZE)
    }

    /// 从物理地址计算物理页号（上取整）
    pub fn ceil(&self) -> PhysPageNum {
        PhysPageNum((self.0 + PAGE_SIZE - 1) / PAGE_SIZE)
    }

    /// 从物理地址获取页内偏移（物理地址的低12位）
    pub fn page_offset(&self) -> usize {
        self.0 & (PAGE_SIZE - 1)
    }

    /// 判断物理地址是否与页面大小对齐
    pub fn is_aligned(&self) -> bool {
        self.page_offset() == 0
    }

    /// 获取一个大小为 T 的不可变切片
    pub fn as_ref<T>(&self) -> &'static T {
        unsafe { (self.0 as *const T).as_ref().unwrap() }
    }

    /// 获取一个大小为 T 的可变切片
    pub fn as_mut<T>(&self) -> &'static mut T {
        unsafe { (self.0 as *mut T).as_mut().unwrap() }
    }
}

impl KernAddr {}

impl From<usize> for KernAddr {
    fn from(value: usize) -> Self {
        Self(value & usize::MAX)
    }
}

impl From<PhysAddr> for KernAddr {
    fn from(pa: PhysAddr) -> Self {
        Self(pa.0 + (KERNEL_DIRECT_OFFSET << PAGE_SIZE_BITS))
    }
}

impl From<KernAddr> for PhysAddr {
    fn from(ka: KernAddr) -> Self {
        Self(ka.0 - (KERNEL_DIRECT_OFFSET << PAGE_SIZE_BITS))
    }
}

impl From<KernAddr> for VirtAddr {
    fn from(ka: KernAddr) -> Self {
        Self(ka.0)
    }
}

impl From<KernAddr> for PhysPageNum {
    fn from(ka: KernAddr) -> Self {
        let pa = PhysAddr::from(ka);
        pa.floor()
    }
}

impl VirtPageNum {
    /// 取出虚拟页号的三级页索引，并按照从高到低的顺序返回
    pub fn indexes(&self) -> [usize; 3] {
        let mut vpn = self.0;
        let mut idx = [0usize; 3];
        for i in (0..3).rev() {
            idx[i] = vpn & 511; // 取出低9位
            vpn >>= 9;
        }
        idx
    }
}

impl PhysPageNum {
    /// 根据自己的PPN取出当前节点的页表项数组
    pub fn as_pte_array(&self) -> &'static mut [PageTableEntry] {
        let pa: PhysAddr = (*self).into();
        unsafe { core::slice::from_raw_parts_mut(pa.0 as *mut PageTableEntry, 512) }
    }

    /// 返回一个字节数组的可变引用，可以以字节为粒度对物理页帧上的数据进行访问
    pub fn as_bytes_array(&self) -> &'static mut [u8] {
        let pa: PhysAddr = (*self).into();
        unsafe { core::slice::from_raw_parts_mut(pa.0 as *mut u8, 4096) }
    }

    /// 获取一个恰好放在一个物理页帧开头的类型为 T 的数据的可变引用
    pub fn as_mut<T>(&self) -> &'static mut T {
        let pa: PhysAddr = (*self).into();
        unsafe { (pa.0 as *mut T).as_mut().unwrap() }
    }
}

/// 虚拟页号范围，是个左闭右开的区间
#[derive(Copy, Clone, Debug)]
pub struct VPNRange {
    start: VirtPageNum,
    end: VirtPageNum,
}

impl VPNRange {
    pub fn new(start: VirtPageNum, end: VirtPageNum) -> Self {
        assert!(start <= end, "start {:?} > end {:?}!", start, end);
        Self { start, end }
    }

    pub fn from_va(start_va: VirtAddr, end_va: VirtAddr) -> Self {
        let start = start_va.floor();
        let end = end_va.ceil();
        assert!(start <= end, "start {:?} > end {:?}!", start, end);

        Self { start, end }
    }

    pub fn get_start(&self) -> VirtPageNum {
        self.start
    }

    pub fn get_end(&self) -> VirtPageNum {
        self.end
    }
}

impl IntoIterator for VPNRange {
    type Item = VirtPageNum;

    type IntoIter = IntoIter<Self::Item>;

    fn into_iter(self) -> Self::IntoIter {
        Self::IntoIter {
            next: self.start,
            end: self.end,
        }
    }
}

pub struct IntoIter<T> {
    next: T,
    end: T,
}

impl<T> Iterator for IntoIter<T>
where
    T: PartialEq + Step,
{
    type Item = T;

    fn next(&mut self) -> Option<Self::Item> {
        if self.next == self.end {
            None
        } else {
            Some(self.next.step())
        }
    }
}

pub trait Step {
    /// 返回当前值后步进 1
    fn step(&mut self) -> Self;
}

impl Step for VirtPageNum {
    fn step(&mut self) -> Self {
        let current = *self;
        self.0 += 1;

        current
    }
}

impl Step for PhysPageNum {
    fn step(&mut self) -> Self {
        let current = *self;
        self.0 += 1;

        current
    }
}

