                    );
                )*
            };
        }
        macro_rules! insert_identical_kernel_vm_areas {
            ($kvmm:ident,$($start:expr, $end:expr, $permission:expr, $file:expr, $page_offset:expr)*) => {
                $(
                    $kvmm.insert(
                        VmArea::new(
                            ($start as usize - (KERNEL_DIRECT_OFFSET << PAGE_SIZE_BITS)).into(),
                            ($end as usize - (KERNEL_DIRECT_OFFSET << PAGE_SIZE_BITS)).into(),
                            MapType::Identical,
                            $permission,
                            $file,
                            $page_offset,
                        ),
                        None
                    );
                )*
            };
        }
        insert_kernel_vm_areas! { memory_set,
            stext,   etext,    MapPermission::R | MapPermission::X, None, 0
            srodata, erodata,  MapPermission::R, None, 0
            sdata,   edata,    MapPermission::R | MapPermission::W, None, 0
            sbss,    ebss,     MapPermission::R | MapPermission::W, None, 0
            // ekernel, VIRT_END, MapPermission::R | MapPermission::W, None, 0
        }

        insert_identical_kernel_vm_areas! { memory_set,
            stext,   etext,    MapPermission::R | MapPermission::X, None, 0
            srodata, erodata,  MapPermission::R, None, 0
            sdata,   edata,    MapPermission::R | MapPermission::W, None, 0
            sbss,    ebss,     MapPermission::R | MapPermission::W, None, 0
            ekernel, VIRT_END, MapPermission::R | MapPermission::W, None, 0
        }
        // 恒等映射 内存映射 I/O (MMIO, Memory-Mapped I/O) 地址到内核地址空间
        for &pair in MMIO {
            insert_kernel_vm_areas!(memory_set,
                pair.0 + (KERNEL_DIRECT_OFFSET << PAGE_SIZE_BITS),
                pair.0+pair.1 + (KERNEL_DIRECT_OFFSET << PAGE_SIZE_BITS),
                MapPermission::R | MapPermission::W,
                None,
                0);
        }

        memory_set
    }));
}

