/// 虚拟地址空间抽象
///
/// 比如，用户进程的虚拟地址空间抽象:
///
/// ```text
/// +--------------------+
/// |     trampoline     |
/// +--------------------+
/// |      trap_cx       |
/// +--------------------+
/// |     Guard Page     | <-- 保护页
/// +--------------------+
/// |                    |
/// |     User Stack     | <-- 用户虚拟地址空间(U-mode)中的用户栈
/// |                    |
/// +--------------------+
/// |       Unused       |
/// +--------------------+
/// |                    |
/// |     mmap Areas     | <-- mmap 区
/// |                    |
/// +--------------------+
/// |                    |
/// |        ...         |
/// |                    |
/// +--------------------+ <-- brk
/// |                    |
/// |                    |
/// |     User Heap      |
/// |                    |
/// |                    |
/// +--------------------+ <-- brk_start
/// |                    |
/// |    Data Segments   | <-- ELF 文件加载后所有 Segment 的集合
/// |                    |
/// +--------------------+
/// ```
pub struct MemorySet {
    pub page_table: Arc<SyncUnsafeCell<PageTable>>,

    vm_areas: Vec<VmArea>,

    mmap_areas: Vec<VmArea>,

    heap_areas: VmArea,

    pub brk_start: usize,
    pub brk: usize,
}

impl MemorySet {
    /// 新建一个空的地址空间
    pub fn new_bare() -> Self {
        Self {
            page_table: Arc::new(SyncUnsafeCell::new(PageTable::new())),
            vm_areas: Vec::new(),
            heap_areas: VmArea::new(
                0.into(),
                0.into(),
                MapType::Framed,
                MapPermission::R | MapPermission::W | MapPermission::U,
                None,
                0,
            ),
            mmap_areas: Vec::new(),
            brk_start: 0,
            brk: 0,
        }
    }

    ///
    pub fn new_bare_with_kern_mapping() -> Self {
        let pgtbl = PageTable::with_kern_mapping();
        Self {
            page_table: Arc::new(SyncUnsafeCell::new(pgtbl)),
            vm_areas: Vec::new(),
            heap_areas: VmArea::new(
                0.into(),
                0.into(),
                MapType::Framed,
                MapPermission::R | MapPermission::W | MapPermission::U,
                None,
                0,
            ),
            mmap_areas: Vec::new(),
            brk_start: 0,
            brk: 0,
        }
    }

    /// 获取当前页表的 token (符合 satp CSR 格式要求的多级页表的根节点所在的物理页号)
    pub fn token(&self) -> usize {
        self.page_table.get_unchecked_mut().token()
    }

    /// 在当前地址空间插入一个 `Framed` 方式映射到物理内存的逻辑段
    pub fn insert_framed_area(
        &mut self,
        start_va: VirtAddr,
        end_va: VirtAddr,
        permission: MapPermission,
    ) {
        self.insert(
            VmArea::new(start_va, end_va, MapType::Framed, permission, None, 0),
            None,
        );
    }

    pub fn remove_mmap_area_with_start_vpn(&mut self, start_vpn: VirtPageNum) {
        if let Some((idx, mmap_area)) = self
            .mmap_areas
            .iter_mut()
            .enumerate()
            .find(|(_, area)| area.vpn_range.get_start() == start_vpn)
        {
            mmap_area.erase_pagetable(&self.page_table);
            self.mmap_areas.remove(idx);
        }
    }

    /// 通过起始虚拟页号删除对应的逻辑段（包括连续逻辑段和离散逻辑段）
    pub fn remove_area_with_start_vpn(&mut self, start_vpn: VirtPageNum) {
        if let Some((idx, vm_area)) = self
            .vm_areas
            .iter_mut()
            .enumerate()
            .find(|(_, area)| area.vpn_range.get_start() == start_vpn)
        {
            vm_area.erase_pagetable(&self.page_table);
            self.vm_areas.remove(idx);
        }
    }

    pub fn remove_area(&mut self, start_va: VirtAddr, end_va: VirtAddr) {
        let mut op = |areas: &mut Vec<VmArea>| {
            let mut len = areas.len();
            let mut idx = 0;
            let start_vpn = start_va.floor();
            let end_vpn = end_va.ceil();
            let mut finish = false;

            while idx < len {
                let area = &mut areas[idx];
                let area_start_vpn = area.start_vpn();
                let area_end_vpn = area.end_vpn();
                let mut area_remove;
                if start_vpn > area_start_vpn && area_end_vpn > end_vpn {
                    // area_start_vpn < start_vpn < end_vpn < area_end_vpn
                    let front = area.split_left_pop(start_vpn, area.permission);
                    let end = area.split_right_pop(end_vpn, area.permission);
                    area_remove = areas.remove(idx);
                    areas.push(front);
                    areas.push(end);
                    finish = true;
                } else if area_start_vpn >= start_vpn
                    && area_start_vpn < end_vpn
                    && area_end_vpn >= end_vpn
                {
                    // start_vpn <= area_start_vpn < end_vpn <= area_end_vpn
                    area_remove = area.split_left_pop(end_vpn, area.permission);
                    idx += 1;
                } else if area_start_vpn <= start_vpn
                    && area_end_vpn > start_vpn
                    && area_end_vpn <= end_vpn
                {
                    // area_start_vpn <= start_vpn < area_end_vpn <= end_vpn
                    area_remove = area.split_right_pop(start_vpn, area.permission);
                    idx += 1;
                } else if area_start_vpn >= start_vpn && area_end_vpn <= end_vpn {
                    // start_vpn <= area_start_vpn < area_end_vpn <= end_vpn
                    area_remove = areas.remove(idx);
                    len -= 1;
                } else {
                    idx += 1;
                    continue;
                }

                area_remove.write_back(&self.page_table).unwrap();
                area_remove.erase_pagetable(&self.page_table);

