            page_offset = 0;
            data_len -= src.len();
            if data_len == 0 {
                break;
            }
            current_vpn.step();
        }
    }

    pub fn lazy_map_vpn(&mut self, vpn: VirtPageNum, page_table: &Arc<SyncUnsafeCell<PageTable>>) {
        self.map_one(page_table, vpn);
    }

    fn map_one(&mut self, page_table: &Arc<SyncUnsafeCell<PageTable>>, vpn: VirtPageNum) {
