}

impl Thread {
    pub fn new(
        process: Arc<Process>,
        _main_thread: Option<&Arc<Thread>>,
        trap_cx: TrapContext,
        ustack_top: usize,
        tid: Option<Arc<TidHandle>>,
    ) -> Self {
        let tid = match tid {
            Some(tid) => tid,
            None => Arc::new(tid_alloc()),
        };
        let thread = Self {
            tid: tid.clone(),
            process: process.clone(),
            inner: UnsafeCell::new(ThreadInner {
                trap_cx,
                ustack_top,
                waker: None,
                terminated: false,
                signals: SigSet::empty(),
            }),
        };
        PROCESS_MANAGER.add(tid.0, &process);
        thread
    }

    /// Construct a new thread from another thread
    pub fn from_another(
        another: &Arc<Thread>,
        new_process: Arc<Process>,
        stack: Option<usize>,
        tid: Option<Arc<TidHandle>>,
        _: CloneFlags,
    ) -> Self {
        let tid = match tid {
            Some(tid) => tid,
            None => Arc::new(tid_alloc()),
        };
        PROCESS_MANAGER.add(tid.0, &new_process);

        Self {
            tid: tid.clone(),
            process: new_process.clone(),
            inner: UnsafeCell::new(ThreadInner {
                trap_cx: {
                    let mut trap_context = another.trap_context();
                    if let Some(stack) = stack {
                        trap_context.set_sp(stack);
                    }
                    trap_context
                },
                ustack_top: unsafe { (*another.inner.get()).ustack_top },
                waker: None,
                terminated: false,
                signals: SigSet::empty(),
            }),
        }
    }

    /// Get the copied trap context
    pub fn trap_context(&self) -> TrapContext {
        unsafe { (*self.inner.get()).trap_cx }
    }

    /// Get the mutable ref of trap context
    pub fn trap_context_mut(&self) -> &mut TrapContext {
        unsafe { &mut (*self.inner.get()).trap_cx }
    }

    /// Get the ref of trap context
    pub fn trap_context_ref(&self) -> &TrapContext {
        unsafe { &(*self.inner.get()).trap_cx }
    }

    /// Terminate this thread
    pub fn terminate(&self) {
        let inner = unsafe { &mut (*self.inner.get()) };
        inner.terminated = true;
    }

    /// Whether this thread has been terminated or not
    pub fn is_zombie(&self) -> bool {
        unsafe { (*self.inner.get()).terminated }
    }

    /// Tid of this thread
    pub fn tid(&self) -> usize {
        self.tid.0
    }

    /// Set waker for this thread
    pub fn set_waker(&self, waker: Waker) {
        unsafe {
            (*self.inner.get()).waker = Some(waker);
        }
    }

    pub fn get_waker(&self) -> Option<&Waker> {
        unsafe { (*self.inner.get()).waker.as_ref() }
    }

    pub fn get_signals(&self) -> &mut SigSet {
        unsafe { &mut (*self.inner.get()).signals }
    }
}

