/// Syscall dispatcher.
pub async fn syscall(id: usize, args: [usize; 6]) -> isize {
    let syscall_id = SyscallId::from(id); // This will check if syscall id is valid.

    // if syscall_id != SyscallId::SyscallId::SYS_BRK {
    //     println!("On hart {}: [{}]", hartid!(), syscall_id);
    // }
    let ret = match syscall_id {
        SyscallId::SYS_CLONE => sys_do_fork(args[0], args[1], args[2], args[3], args[4]),

        SyscallId::SYS_EXECVE => sys_exec(
            args[0] as *const u8,
            args[1] as *const usize,
            args[2] as *const u8,
        ),

        SyscallId::SYS_LINKAT => sys_linkat(
            args[0] as isize,
            args[1] as *const u8,
            args[2] as isize,
            args[3] as *const u8,
            args[4] as u32,
        ),
        SyscallId::SYS_OPENAT => sys_openat(
            args[0] as isize,
            args[1] as *const u8,
            args[2] as u32,
            args[3] as u32,
        ),

        SyscallId::SYS_GETCWD => sys_getcwd(args[0] as *mut u8, args[1]),
        SyscallId::SYS_DUP => sys_dup(args[0]),
        SyscallId::SYS_DUP3 => sys_dup3(args[0], args[1]),
        SyscallId::SYS_MKDIRAT => {
            sys_mkdirat(args[0] as isize, args[1] as *const u8, args[2] as u32)
        }
        SyscallId::SYS_UNLINKAT => {
            sys_unlinkat(args[0] as isize, args[1] as *const u8, args[2] as u32)
        }
        SyscallId::SYS_UMOUNT2 => sys_umount2(args[0], args[1] as u32).await,
        SyscallId::SYS_MOUNT => sys_mount(
            args[0] as *const u8,
            args[1] as *const u8,
            args[2] as *const u8,
            args[3] as u32,
            args[4] as *const u8,
        ),
        SyscallId::SYS_CHDIR => sys_chdir(args[0] as *const u8),
        SyscallId::SYS_CLOSE => sys_close(args[0]),
        SyscallId::SYS_PIPE2 => sys_pipe2(args[0] as *mut i32, args[1] as u32),
        SyscallId::SYS_GETDENTS64 => sys_getdents64(args[0] as isize, args[1], args[2]),
        SyscallId::SYS_READ => sys_read(args[0], args[1], args[2]).await,
        SyscallId::SYS_WRITE => sys_write(args[0], args[1], args[2]).await,
        SyscallId::SYS_FSTAT => sys_fstat(args[0] as isize, args[1]),
        SyscallId::SYS_EXIT => sys_exit(args[0] as i8),
        SyscallId::SYS_NANOSLEEP => sys_nanosleep(args[0]).await,
        SyscallId::SYS_SCHED_YIELD => sys_sched_yield().await,
        SyscallId::SYS_TIMES => sys_times(args[0] as *const u8),
        SyscallId::SYS_UNAME => sys_uname(args[0] as *const u8),
        SyscallId::SYS_GETTIMEOFDAY => sys_gettimeofday(args[0] as *const u8),
        SyscallId::SYS_GETPID => sys_getpid(),
        SyscallId::SYS_GETPPID => sys_getppid(),
        SyscallId::SYS_BRK => sys_brk(args[0]),
        SyscallId::SYS_MMAP => sys_mmap(
            args[0],
            args[1],
            args[2],
            args[3],
            args[4] as isize,
            args[5],
        ),
        SyscallId::SYS_MUNMAP => sys_munmap(args[0], args[1]),
        SyscallId::SYS_WAIT4 => sys_wait4(args[0] as isize, args[1], args[2] as i32).await,

        _ => panic!("unsupported syscall, syscall id: {:?}", syscall_id),
    };
    match ret {
        Ok(data) => data,
        Err(err) => {
            let errno = err as isize;
            if errno > 0 {
                -errno
            } else {
                errno
            }
        }
    }
}

