/// #define SYS_getcwd 17
///
/// 功能：获取当前工作目录；
///
/// 输入：
///
/// - char *buf：一块缓存区，用于保存当前工作目录的字符串。当buf设为NULL，由系统来分配缓存区。
/// - size：buf 缓存区的大小。
///
/// 返回值：
///
/// - 成功：返回当前工作目录的字符串的指针。
/// - 失败：则返回NULL。
///
/// ```c
/// char *buf, size_t size;
/// long ret = syscall(SYS_getcwd, buf, size);
/// ```
pub fn sys_getcwd(buf: *mut u8, size: usize) -> Result {
    if buf as usize == 0 {
        return_errno!(Errno::EFAULT, "buf is NULL");
    }
    if buf as usize != 0 && size == 0 {
        return_errno!(Errno::EINVAL, "buf is not NULL but size is zero");
    }

    let token = current_user_token();
    let process = current_process();
    let inner = process.inner.lock();

    let buf_vec = translated_bytes_buffer(token, buf, size);
    let mut userbuf = UserBuffer::wrap(buf_vec);
    let cwd = inner.cwd.to_string();
    let cwd_str = cwd.as_bytes();
    userbuf.write(cwd_str);
    userbuf.write_at(cwd_str.len(), &[0]); // 添加字符串末尾的\0
    Ok(buf as isize)
}

/// #define SYS_pipe2 59
///
/// 功能：创建管道；
///
/// 输入：
///
/// - fd\[2\]：用于保存2个文件描述符。
///     - fd\[0\] 为管道的读出端
///     - fd\[1\] 为管道的写入端。
///
/// 返回值：
///
/// - 成功执行，返回0。
/// - 失败，返回-1。
///
/// ```c
/// int fd[2];
/// int ret = syscall(SYS_pipe2, fd, 0);
/// ```
pub fn sys_pipe2(pipe: *mut i32, flags: u32) -> Result {
    let flags = OpenFlags::from_bits(flags).ok_or(Errno::EINVAL)?;
    let (pipe_read, pipe_write) = make_pipe::<PIPE_CAPACITY>(Some(flags));

    let (read_fd, write_fd) = current_process().inner_handler(move |proc| {
        let read_fd = proc.alloc_fd();
        if read_fd == FD_LIMIT {
            return_errno!(Errno::EMFILE);
        }
        proc.fd_table[read_fd] = Some(pipe_read);

        let write_fd = proc.alloc_fd();
        if write_fd == FD_LIMIT {
            return_errno!(Errno::EMFILE);
        }
        proc.fd_table[write_fd] = Some(pipe_write);

        Ok((read_fd, write_fd))
    })?;

    let _sum_guard = SumGuard::new();

    let sz = core::mem::size_of::<i32>();
    let buf = unsafe { core::slice::from_raw_parts_mut(pipe, 2 * sz) };
    buf[0] = read_fd as i32;
    buf[1] = write_fd as i32;
    log::debug!("[sys_pipe]: read fd {}, write fd {}", read_fd, write_fd);
    Ok(0)
}

/// #define SYS_dup 23
///
/// 功能：复制文件描述符；
///
/// 输入：
///
/// - fd：被复制的文件描述符。
///
/// 返回值：
///
/// - 成功：返回新的文件描述符。
/// - 失败：返回-1。
///
/// ```c
/// int fd;
/// int ret = syscall(SYS_dup, fd);
/// ```
pub fn sys_dup(fd: usize) -> Result {
    let process = current_process();
    let mut inner = process.inner.lock();

    // 检查传入 fd 的合法性
    if fd >= inner.fd_table.len() {
        return_errno!(Errno::EBADF, "oldfd is out of range, oldfd: {}", old_fd);
    }
    if inner.fd_table[fd].is_none() {
        return_errno!(Errno::EBADF, "oldfd is not exist, oldfd {}", old_fd);
    }
    let new_fd = inner.alloc_fd();
    if new_fd > FD_LIMIT {
        return_errno!(Errno::EMFILE, "too many fd, newfd: {}", new_fd);
    }
    inner.fd_table[new_fd] = Some(Arc::clone(inner.fd_table[fd].as_ref().unwrap()));

    Ok(new_fd as isize)
}

/// #define SYS_dup3 24
///
/// 功能：复制文件描述符，并指定了新的文件描述符；
///
/// 输入：
///
/// - old：被复制的文件描述符。
/// - new：新的文件描述符。
///
/// 返回值：
///
/// - 成功：返回新的文件描述符。
/// - 失败：返回-1。
///
/// ```c
/// int old, int new;
/// int ret = syscall(SYS_dup3, old, new, 0);
/// ```
pub fn sys_dup3(old_fd: usize, new_fd: usize) -> Result {
    let process = current_process();
    let mut inner = process.inner.lock();

    if old_fd >= inner.fd_table.len() || new_fd > FD_LIMIT {
        return_errno!(Errno::EBADF);
    }
    if inner.fd_table[old_fd].is_none() {
        return_errno!(Errno::EBADF);
    }
    if new_fd >= inner.fd_table.len() {
        for _ in inner.fd_table.len()..(new_fd + 1) {
            inner.fd_table.push(None);
        }
    }

    inner.fd_table[new_fd] = Some(inner.fd_table[old_fd].as_ref().unwrap().clone());
    Ok(new_fd as isize)
}

/// #define SYS_chdir 49
///
/// 功能：切换工作目录；
