/// 返回值：
///
/// - 成功：返回0。
/// - 失败：返回-1。
///
/// ```c
/// const char *path;
/// int ret = syscall(SYS_chdir, path);
/// ```
pub fn sys_chdir(path: *const u8) -> Result {
    let _sum_guard = SumGuard::new();
    let token = current_user_token();
    let path = translated_str(token, path);
    let path = if path::is_relative_path(&path) {
        path::change_relative_to_absolute(
            &path,
            &current_process()
                .inner_handler(move |proc| proc.cwd.clone())
                .to_string(),
        )
    } else {
        path.clone()
    };
    let target_inode = <dyn Inode>::lookup_from_root(&path)?.0;
    match target_inode {
        Some(target_inode) => {
            let mut inner_lock = target_inode.metadata().inner.lock();
            inner_lock.last_atime = timer::get_time_spec();
            match inner_lock.state {
                InodeState::SyncedBoth => {
                    inner_lock.state = InodeState::DirtyInode;
                }
                InodeState::DirtyData => {
                    inner_lock.state = InodeState::DirtyBoth;
                }
                _ => {}
            }
            // TODO: add to fs's dirty list
            if target_inode.metadata().file_type == FileType::FileDIR {
                log::debug!("[sys_chdir] change cwd to {}", path);
                current_process()
                    .inner_handler(move |proc| proc.cwd = path::AbsolutePath::from_string(path));
                Ok(0)
            } else {
                Err(Errno::ENOTDIR)
            }
        }
        None => Err(Errno::ENOENT),
    }
}

