/// #define SYS_clone 220
///
/// 功能：创建一个子进程；
///
/// 输入：
///
/// - flags: 创建的标志，如SIGCHLD；
/// - stack: 指定新进程的栈，可为0；
/// - ptid: 父线程ID；
/// - tls: TLS线程本地存储描述符；
/// - ctid: 子线程ID；
///
/// 返回值：成功则返回子进程的线程ID，失败返回-1；
///
/// ```c
/// pid_t ret = syscall(SYS_clone, flags, stack, ptid, tls, ctid)
/// ```
pub fn sys_do_fork(
    flags: usize,
    stack_ptr: usize,
    _ptid: usize,
    _tls: usize,
    _ctid: usize,
) -> Result {
    let current_process = current_process();
    let flags = CloneFlags::from_bits(flags & !0xff).unwrap();
    let new_process = current_process.fork(flags);

    if stack_ptr != 0 {
        new_process
            .main_thread()
            .unwrap()
            .upgrade()
            .unwrap()
            .trap_context_mut()
            .set_sp(stack_ptr);
    }

    let new_pid = new_process.pid();
    debug!("fork a new process, pid is {}", new_pid.clone());
    Ok(new_pid as isize) // 对于父进程，返回值是子进程的 PID
}

/// #define SYS_execve 221
///
/// 功能：执行一个指定的程序；
///
/// 输入：
///
/// - path: 待执行程序路径名称，
/// - argv: 程序的参数，
/// - envp: 环境变量的数组指针
///
/// 返回值：成功不返回，失败返回-1；
///
/// ```c
/// const char *path, char *const argv[], char *const envp[];
/// int ret = syscall(SYS_execve, path, argv, envp);
/// ```
pub fn sys_exec(path: *const u8, mut argv: *const usize, mut envp: *const u8) -> Result {
    debug!("start to exec!!");
    let token = current_user_token();
    // 读取到用户空间的应用程序名称（路径）
    let path = translated_str(token, path);
    let mut args_vec: Vec<String> = Vec::new();
    if argv as usize != 0 {
        loop {
            let arg_str_ptr = *translated_ref(token, argv);
            if arg_str_ptr == 0 {
                // 读到下一参数地址为0表示参数结束
                break;
            } // 否则从用户空间取出参数，压入向量
            args_vec.push(translated_str(token, arg_str_ptr as *const u8));
            unsafe {
                argv = argv.add(1);
            }
        }
    }

    // 环境变量
    let mut envs_vec: Vec<String> = Vec::new();
    if envp as usize != 0 {
        loop {
            let env_str_ptr = *translated_ref(token, envp);
            if env_str_ptr == 0 {
                // 读到下一参数地址为0表示参数结束
                break;
            } // 否则从用户空间取出参数，压入向量
            envs_vec.push(translated_str(token, env_str_ptr as *const u8));
            unsafe {
                envp = envp.add(1);
            }
        }
    }

    let process = current_process();
    let inner = process.inner.lock();
    let new_path = inner.cwd.clone().join_string(path);
    let app_inode = path2inode_flags(0, &new_path.to_string(), OpenFlags::RDONLY);
    if app_inode.is_err() {
        // log::warn!("[sys_execve] cannot find file {}", path);
        return Err(app_inode.err().unwrap());
    }
    let app_inode = app_inode.unwrap();
    let app_file = inode_to_file(app_inode, None);
    drop(inner);
    process.exec(app_file, args_vec, envs_vec);
    debug!("exec finish");
    Ok(0_isize)
}

bitflags! {
    struct WaitOption: i32 {
        const WNOHANG = 1;
        const WUNTRACED = 1 << 1;
        const WCONTINUED = 1 << 3;
    }
}

type Pid = usize;
struct WaitFuture {
    options: WaitOption,
    pid: Pid,
    exit_status_addr: usize,
}

impl WaitFuture {
    fn new(options: WaitOption, pid: Pid, exit_status_addr: usize) -> Self {
        Self {
            options,
            pid,
            exit_status_addr,
        }
    }
}

impl Future for WaitFuture {
    type Output = Result;

    fn poll(
        self: core::pin::Pin<&mut Self>,
        _cx: &mut core::task::Context<'_>,
    ) -> core::task::Poll<Self::Output> {
        let process = current_process();
        if let Some((child_pid, exit_code)) = process.inner_handler(|proc| {
            if process.pid() == INITPROC_PID && proc.children.is_empty() {
                debug!("Initial process waits for nothing; OS will exit");
                println!("[kernel] shutdown...");
                shutdown();
            }
            if !proc
                .children
                .iter()
                .any(|p| self.pid as isize == -1 || self.pid == p.pid())
            {
                debug!(
                    "[sys_wait4] proc[{}]: no such pid {} | exit code address {:#x}",
                    current_process().pid(),
                    self.pid,
                    self.exit_status_addr
                );
                return Err(Errno::ECHILD);
            }
            let idx = proc
                .children
                .iter()
                .enumerate()
                .find(|(_, p)| p.is_zombie() && (self.pid as isize == -1 || self.pid == p.pid()))
                .map(|(idx, _)| idx);

            if let Some(idx) = idx {
                let child = proc.children.remove(idx);
                let target_pid = child.pid();
                let exit_code = child.exit_code();
                debug!(
                    "[sys_wait4] found pid {} | exit code {}",
                    target_pid, exit_code
                );
                Ok(Some((target_pid, exit_code as i32)))
            } else {
                debug!("[sys_wait4] child process still not finish; keep waiting~");
                Ok(None)
            }
        })? {
            if self.exit_status_addr != 0 {
                let _sum_guard = SumGuard::new();
                let exit_status_ptr = self.exit_status_addr as *mut i32;
                debug!(
                    "[sys_wait4] write pid to exit_status_ptr {:#x} before",
                    self.exit_status_addr
                );
                unsafe {
                    exit_status_ptr.write_volatile((exit_code & 0xff) << 8);
                    debug!(
                        "[sys_wait4] write pid to exit_code_ptr after, exit code {:#x}",
                        (*exit_status_ptr & 0xff00) >> 8
                    );
                }
            }
            debug!("[sys_wait4] ret {}", child_pid);
            Poll::Ready(Ok(child_pid as isize))
        } else if self.options.contains(WaitOption::WNOHANG) {
            Poll::Ready(Ok(0))
        } else {
            current_add_signal(SigSet::SIGCHLD);
            Poll::Pending
        }
    }
}

