/// #define SYS_nanosleep 101
///
/// 功能：执行线程睡眠，sleep()库函数基于此系统调用；
///
/// 输入：睡眠的时间间隔；
///
/// 返回值：成功返回0，失败返回-1;
///
/// ```c
/// const struct timespec *req, struct timespec *rem;
/// int ret = syscall(SYS_nanosleep, req, rem);
/// ```
pub async fn sys_nanosleep(buf: usize) -> Result {
    let token = current_user_token();
    let len_timeval = translated_ref(token, buf as *const TimeSpec);
    let len = len_timeval.tv_sec * 1000 + len_timeval.tv_nsec / 1000000;
    ksleep(Duration::from_millis(len as u64)).await;
    Ok(0)
}

