/// trap 初始化
///
/// 在内核初始化阶段发生的 trap 为 S 特权器的 trap，设置成相应的内核态 trap 处理函数 [`kernel_trap_handler`]
pub fn init() {
    set_kernel_trap_entry();
}

/// 设置内核态下的 trap 入口
///
/// 在内核态发生 trap 后，CPU 会跳转执行 [`kernel_trap_handler`] 处的代码
fn set_kernel_trap_entry() {
    unsafe { stvec::write(kern_trapvec as usize, TrapMode::Direct) }
}

/// 设置用户态下的 trap 入口
///
/// 在用户态发生 trap 后，CPU 会跳转执行 [`TRAMPOLINE`] 处的代码
fn set_user_trap_entry() {
    unsafe { stvec::write(user_trapvec as usize, TrapMode::Direct) }
}

/// 使能 S 特权级时钟中断
pub fn enable_stimer_interrupt() {
    unsafe { sie::set_stimer() }
}

#[no_mangle]
pub fn trap_return() {
    close_interrupt();

    set_user_trap_entry();

    extern "C" {
        fn user_trapret(cx: *mut TrapContext);
    }

    if let Some((errno, msg)) = check_current_signals() {
        debug!("trap_return: {}", msg);
        exit_and_terminate_all_threads(errno);
    }

    unsafe {
        user_trapret(current_trap_cx());
    }
}

//! trap 处理模块
//!
//! 根据 trap 发生的原因进行分发处理

use super::set_kernel_trap_entry;
use crate::{
    consts::USER_SPACE_END,
    mm::VirtAddr,
    process::{current_add_signal, signal_flags::SigSet, thread::schedule::yield_now},
    processor::{current_process, current_trap_cx, open_interrupt},
    syscall::dispatcher::syscall,
    timer::{handle_timeout_events, set_next_trigger},
};
use log::{debug, error};
use riscv::register::{
    scause::{self, Exception, Interrupt, Trap},
    sepc, stval,
};

/// 用户态 trap 发生时的处理函数
#[no_mangle]
pub async fn user_trap_handler() {
    set_kernel_trap_entry();

    // 用于描述 Trap 的原因
    let scause = scause::read();
    // 给出 Trap 附加信息
    let stval = stval::read();

    open_interrupt();

    match scause.cause() {
        Trap::Exception(Exception::UserEnvCall) => {
            let mut cx = current_trap_cx();

            cx.sepc += 4;

            let result = syscall(
                cx.a7(),
                [cx.a0(), cx.a1(), cx.a2(), cx.a3(), cx.a4(), cx.a5()],
            )
            .await;

            // cx is changed during sys_exec, so we have to call it again
            cx = current_trap_cx();
            cx.x[10] = result as usize;
        }

        Trap::Exception(Exception::StoreFault)
        | Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::LoadFault)
        | Trap::Exception(Exception::LoadPageFault) => {
            debug!(
                "user_trap_handler: memory fault, task: {} at {:?}, {:?}",
                current_process().pid(),
                VirtAddr::from(stval),
                VirtAddr::from(stval).floor(),
            );

            let is_load = scause.cause() == Trap::Exception(Exception::LoadFault)
                || scause.cause() == Trap::Exception(Exception::LoadPageFault);

            let va: VirtAddr = stval.into();
            if va > USER_SPACE_END.into() {
                println!("[kernel trap] VirtAddr out of range!");
                current_add_signal(SigSet::SIGSEGV);
            }
            let task = current_process();

            debug!("user_trap_handler: lazy mapping, task: {:?}", task.pid());

            let lazy = task.check_lazy(va, is_load);

            if lazy != 0 {
                current_add_signal(SigSet::SIGSEGV);
            }
        }

        Trap::Exception(Exception::InstructionFault)
        | Trap::Exception(Exception::InstructionPageFault) => {
            debug!(
                "{:?} in application {}, bad addr = {:#x}, bad instruction = {:#x}.",
                scause.cause(),
                current_process().pid(),
                stval,
                current_trap_cx().sepc,
            );

            current_add_signal(SigSet::SIGSEGV);
        }

        Trap::Exception(Exception::IllegalInstruction) => {
            println!("stval:{}", stval);

            let sepc = riscv::register::sepc::read();
            println!("sepc:0x{:x}", sepc);

            current_add_signal(SigSet::SIGILL);
        }

        // 时间片到了
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            handle_timeout_events();
            set_next_trigger();
            log::debug!(
                "[user_trap_handler] timer interrupt, sepc = {:#x}",
                current_trap_cx().sepc
            );
            yield_now().await;
        }

        _ => panic!(
            "trap {:?} is unsupported, stval = {:#x}, sepc = {:#x}!",
            scause.cause(),
            stval,
            sepc::read(),
        ),
    }
}

/// 内核态 trap 发生时的处理函数
#[no_mangle]
pub fn kernel_trap_handler() {
    debug!("enter kernel trap handler");
    let scause = scause::read();
    match scause.cause() {
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            debug!(
                "[kernel_trap_handler] timer interrupt, sepc = {:#x}",
                sepc::read()
            );
            handle_timeout_events();
            set_next_trigger();
        }

        Trap::Exception(Exception::StorePageFault) => {
            let stval = stval::read();
            debug!(
                "kernel_trap_handler: memory fault, task: {} at {:?}, {:?}",
                current_process().pid(),
                VirtAddr::from(stval),
                VirtAddr::from(stval).floor(),
            );
            let task = current_process();
            let va: VirtAddr = stval.into();
            debug!(
                "[kernel_trap_handler] lazy mapping, process#{:?}",
                task.pid()
            );
            let lazy = task.check_lazy(va, false);
            if lazy != 0 {
                current_add_signal(SigSet::SIGSEGV);
            }
        }

        _ => {
            error!(
                "[kernel_trap_handler] {:?}(scause:{}) | stval = {:#x}, sepc = {:#x}",
                scause::read().cause(),
                scause::read().bits(),
                stval::read(),
                sepc::read()
            );
            panic!(
                "a trap {:?} from kernel! stval {:#x}",
                scause::read().cause(),
                stval::read()
            );
        }
    }
}

use riscv::register::sstatus::{self, Sstatus, SPP};
#[derive(Clone, Copy, Debug)]
#[repr(C)]
pub struct TrapContext {
    /// --- states before trap
    /// general regs[0..31]
    pub x: [usize; 32],
    /// CSR 
    pub sstatus: Sstatus, // 32
    pub sepc: usize,      // 33

    /// --- states after trap
    pub kern_sp: usize,   // 34
    pub kern_ra: usize,   // 35
    pub s: [usize; 12],   // [36..47]
    pub kern_fp: usize,
    pub kern_tp: usize,   // 48
}

impl TrapContext {
    pub fn app_init_context(
        entry: usize,
        sp: usize,
    ) -> Self {
        let mut sstatus = sstatus::read();
        sstatus.set_spp(SPP::User);
        sstatus.set_sie(false);
        sstatus.set_spie(false);
        let mut cx = Self {
            x: [0; 32],
            sstatus,
            sepc: entry, 
            kern_sp: 0,
            kern_ra: 0,
            s: [0; 12],
            kern_fp: 0,
            kern_tp: 0,
        };
        cx.set_sp(sp);
        cx
    }

    /// 通用寄存器 `x0`
    #[allow(unused)]
    #[inline(always)]
    pub fn zero(&self) -> usize {
        0
    }
}

