pub fn init() {
    println!("===+ FS init start +===");
    INODE_CACHE.init();
    *BLOCK_DEVICE.lock() = Some(Arc::new(VirtIOBlock::new()));
    FILE_SYSTEM_MANAGER
        .mount(
            "/",
            "/dev/mmcblk0",
            FsDevice::BlockDevice(BLOCK_DEVICE.lock().as_ref().unwrap().clone()),
            FileSystemType::VFAT,
            StatFlags::ST_NOSUID,
        )
        .expect("rootfs init fail!");
    list_rootfs();

    let root_inode = FILE_SYSTEM_MANAGER.root_inode();

    println!("===+ FS init finish +===");
}

#[allow(unused)]
pub fn print_dir_tree() {
    debug!("------------ dir tree: ------------");
    let parent = Arc::clone(&FILE_SYSTEM_MANAGER.root_inode());
    print_dir_recursively(parent, 1);
}

fn print_dir_recursively(inode: Arc<dyn Inode>, level: usize) {
    let children = inode.metadata().inner.lock().children_inodes.clone();
    for child in children {
        for _ in 0..level {
            print!("-");
        }
        println!("{}", child.0);
        print_dir_recursively(child.1, level + 1);
    }
}

pub fn ffi_path2inode_flags(
    dirfd: isize,
    path: *const u8,
    flags: OpenFlags,
) -> GeneralResult<Arc<dyn Inode>> {
    if flags.contains(OpenFlags::CREATE) {
        let (inode, path, parent) = utils::path::ffi_path2inode(dirfd, path, true)?;
        if let Some(inode) = inode {
            Ok(inode)
        } else {
            try_create_inode(parent, path, flags)
        }
    } else {
        let (inode, path, parent) = utils::path::ffi_path2inode(dirfd, path, false)?;
        if let Some(inode) = inode {
            Ok(inode)
        } else {
            try_create_inode(parent, path, flags)
        }
    }
}

pub fn path2inode_flags(
    dirfd: isize,
    path: &str,
    flags: OpenFlags,
) -> GeneralResult<Arc<dyn Inode>> {
    if flags.contains(OpenFlags::CREATE) {
        let (inode, path, parent) = utils::path::path_to_inode(dirfd, Some(path), true)?;
        if let Some(inode) = inode {
            Ok(inode)
        } else {
            try_create_inode(parent, path, flags)
        }
    } else {
        let (inode, path, parent) = utils::path::path_to_inode(dirfd, Some(path), false)?;
        if let Some(inode) = inode {
            Ok(inode)
        } else {
            try_create_inode(parent, path, flags)
        }
    }
}

fn try_create_inode(
    parent: Option<Arc<dyn Inode>>,
    path: String,
    flags: OpenFlags,
) -> GeneralResult<Arc<dyn Inode>> {
    if flags.contains(OpenFlags::CREATE) {
        let parent = match parent {
            Some(parent) => parent,
            None => {
                //wyz:我觉得不会有这种情况
                println!("[create_inode_if_need]:parent is none");
                let parent_path = utils::path::get_parent_dir(&path).unwrap();
                <dyn Inode>::lookup_from_root(&parent_path)
                    .ok()
                    .unwrap()
                    .0
                    .unwrap()
            }
        };
        let child_name = utils::path::get_name(&path);
        debug!("create file {}", path);
        let res = {
            if flags.contains(OpenFlags::DIRECTORY) {
                parent.mkdir_v(child_name, FileType::FileDIR).unwrap()
            } else {
                // TODO dev id
                parent.mknod_v(child_name, FileType::FileREG, None).unwrap()
            }
        };
        Ok(res)
    } else {
        debug!("parent dir {} doesn't exist", path);
        Err(Errno::ENOENT)
    }
}

fn list_rootfs() {
    let root_inode = FILE_SYSTEM_MANAGER.root_inode();
    if !root_inode.metadata().inner.lock().is_all_load {
        root_inode.load_children(root_inode.clone(), None);
    }
    for sb in root_inode.metadata().inner.lock().children_inodes.iter() {
        println!("----| {}", sb.0);
    }
}

pub fn inode_to_file(inode: Arc<dyn Inode>, flags: Option<OpenFlags>) -> Arc<dyn File> {
    match flags {
        Some(flags) => {
            let file: Arc<dyn File> = inode
                .get_vfile(inode.clone(), Some(flags))
                .expect("Failed to get file from inode");
            file
        }
        None => {
            let file: Arc<dyn File> = inode.get_vfile(inode.clone(), None).unwrap();
            file
        }
    }
}

pub fn file_to_inode(file: &Arc<dyn File>) -> Arc<dyn Inode> {
    let inode: Arc<dyn Inode> = file.metadata().inner_get(|inner| {
        let inode = inner
            .inode
            .as_ref()
            .expect("Failed to get inode from file")
            .clone();
        inode
    });
    inode
}

