impl InodeMeta {
    pub fn new(
        parent: Option<Arc<dyn Inode>>,
        path: &str,
        mode: FileType,
        data_len: usize,
        device: Option<InodeDevice>,
    ) -> Self {
        let name = path::get_name(path);
        let parent = parent.map(|parent| Arc::downgrade(&parent));
        Self {
            ino: INODE_NUMBER.fetch_add(1, Ordering::Relaxed),
            file_type: mode,
            device_no: None,
            device,
            file_path: path.to_string(),
            file_name: name.to_string(),
            inner: Mutex::new(InodeMetaInner {
                last_atime: TimeSpec::new(),
                last_mtime: TimeSpec::new(),
                last_stime: TimeSpec::new(),
                parent_inode: parent,
                children_inodes: BTreeMap::new(),
                page_cache: None,
                data_len,
                state: InodeState::InitAll,
                lookup_hint: 0,
                is_all_load: false,
            }),
        }
    }
}
