pub trait File: Send + Sync {
    /// For default file, data must be read from page cache first.
    /// Note that only guarantee the safety of the first PAGE_SIZE bytes

    fn read<'a>(&'a self, buf: &'a mut [u8], flags: OpenFlags) -> AsyscallResult;
    /// For default file, data must be written to page cache first.
    fn write<'a>(&'a self, buf: &'a [u8], flags: OpenFlags) -> AsyscallResult;

    fn pread<'a>(&'a self, buf: &'a mut [u8], off: usize) -> AsyscallResult {
        Box::pin(async move {
            self.metadata().lock.lock().await;
            let old_off = self.seek(SeekFrom::Current(0))?;
            self.seek(SeekFrom::Start(off))?;
            let ret = self.read(buf, OpenFlags::default()).await;
            self.seek(SeekFrom::Start(old_off as usize))?;
            ret
        })
    }

    fn pwrite<'a>(&'a self, buf: &'a [u8], off: usize) -> AsyscallResult {
        Box::pin(async move {
            self.metadata().lock.lock().await;
            let old_off = self.seek(SeekFrom::Current(0))?;
            self.seek(SeekFrom::Start(off))?;
            let ret = self.write(buf, OpenFlags::default()).await;
            self.seek(SeekFrom::Start(old_off as usize))?;
            ret
        })
    }
    /// For default file, data must be read from page cache first
    fn sync_read(&self, buf: &mut [u8]) -> Result {
        block_on(self.read(buf, OpenFlags::default()))
    }

    /// For default file, data must be written to page cache first
    fn sync_write(&self, buf: &[u8]) -> Result {
        block_on(self.write(buf, OpenFlags::default()))
    }

    fn sync_pread(&self, buf: &mut [u8], off: usize) -> Result {
        block_on(self.pread(buf, off))
    }

    fn sync_pwrite(&self, buf: &[u8], off: usize) -> Result {
        block_on(self.pwrite(buf, off))
    }

    fn pollin(&self, _waker: Option<Waker>) -> GeneralResult<bool> {
