        Ok(true)
        // todo!()
    }

    fn pollout(&self, _waker: Option<Waker>) -> GeneralResult<bool> {
        debug!("[File::pollout] enter default");
        Ok(true)
        // todo!()
    }

    /// Return the new offset
    fn seek(&self, pos: SeekFrom) -> Result {
        let mut meta = self.metadata().inner.lock();
        match pos {
            SeekFrom::Current(off) => {
                // debug!("[DefaultFile::seek] off: {}, pos: {}", off, meta.pos);
                if off < 0 {
                    meta.read_offset -= off.unsigned_abs();
                } else {
                    meta.read_offset += off as usize;
                }
            }
            SeekFrom::Start(off) => {
                meta.read_offset = off;
            }
            SeekFrom::End(off) => {
                let data_len = meta
                    .inode
                    .as_ref()
                    .ok_or(Errno::EINVAL)?
                    .metadata()
                    .inner
                    .lock()
                    .data_len;
                if off < 0 {
                    meta.read_offset = data_len - off.unsigned_abs();
                } else {
                    meta.read_offset = data_len + off as usize;
                }
            }
        }
        Ok(meta.read_offset as isize)
        // self.metadata().inner.lock().pos = offset;
        // Ok(offset  )
    }
