pub struct Pipe<const N: usize> {
    is_readable: bool,
    is_writable: bool,
    buffer: Arc<Mutex<PipeRingBuffer<N>>>,
    meta: FileMetadata,
}

impl<const N: usize> File for Pipe<N> {
    fn metadata(&self) -> &FileMetadata {
        &self.meta
    }

    fn seek(&self, _pos: SeekFrom) -> Result {
        Err(Errno::ESPIPE)
    }

    fn read<'a>(&'a self, buf: &'a mut [u8], _flags: OpenFlags) -> AsyscallResult {
        log::debug!("[Pipe::read] start to pipe read {} bytes", buf.len());
        let buf_addr = buf.as_ptr() as usize;
        Box::pin(async move {
            debug!("start to pipe read {} bytes", buf.len());
            PipeFuture::new(
                self.buffer.clone(),
                buf_addr,
                buf.len(),
                PipeOperation::Read,
            )
            .await
        })
    }

    fn write<'a>(&'a self, buf: &'a [u8], _flags: OpenFlags) -> AsyscallResult {
        log::debug!("[Pipe::write] start to pipe write {} bytes", buf.len());
        let buf_addr = buf.as_ptr() as usize;
        Box::pin(async move {
            debug!("start to pipe write {} bytes", buf.len());
            PipeFuture::new(
                self.buffer.clone(),
                buf_addr,
                buf.len(),
                PipeOperation::Write,
            )
            .await
        })
    }

    fn pollin(&self, waker: Option<Waker>) -> GeneralResult<bool> {
        debug!("[Pipe::pollin] enter");
        self.inner_handler(|ring_buffer| {
            if ring_buffer.available_read() > 0 || ring_buffer.all_write_ends_closed() {
                Ok(true)
            } else {
                debug!("[Pipe::pollin]: no available read");
                if let Some(waker) = waker {
                    ring_buffer.wait_for_reading(waker)
                }
                Ok(false)
            }
        })
    }

    fn pollout(&self, waker: Option<Waker>) -> GeneralResult<bool> {
        self.inner_handler(|ring_buffer| {
            if ring_buffer.available_write() > 0 || ring_buffer.all_read_ends_closed() {
                Ok(true)
            } else {
                debug!("[Pipe::pollout]: no available write");
                if let Some(waker) = waker {
                    ring_buffer.wait_for_writing(waker)
