impl<const N: usize> Pipe<N> {
    fn new(flags: OpenFlags, buffer: Arc<Mutex<PipeRingBuffer<N>>>) -> Self {
        let readable = flags.contains(OpenFlags::RDONLY);
        let writable = flags.contains(OpenFlags::WRONLY);
        let meta = FileMetadata::new(FileType::FileFIFO, Some(flags));
        Self {
            is_readable: readable,
            is_writable: writable,
            buffer,
            meta,
        }
    }

    fn inner_handler<T>(&self, f: impl FnOnce(&mut PipeRingBuffer<N>) -> T) -> T {
        f(&mut self.buffer.lock())
    }
}

impl<const N: usize> Drop for Pipe<N> {
    fn drop(&mut self) {
        log::debug!("[Pipe::drop] start drop..., writable {}", self.is_writable);
        if self.is_writable {
            // Write end,
            // we should wake up all read waiters(if any)
            let mut buffer = self.buffer.lock();
            while let Some(waker) = buffer.read_waiters.pop() {
                log::debug!("[Pipe::drop] wake up");
                waker.wake();
            }
        } else if self.is_readable {
            let mut buffer = self.buffer.lock();
            while let Some(waker) = buffer.write_waiters.pop() {
                log::debug!("[Pipe::drop] wake up");
                waker.wake();
            }
        }
    }
}

