pub struct FileSystemManager {
    pub fs_manager: SpinNoIrqLock<BTreeMap<String, Arc<dyn FileSystem>>>,
}

impl FileSystemManager {
    pub const fn new() -> Self {
        Self {
            fs_manager: SpinNoIrqLock::new(BTreeMap::new()),
        }
    }
    pub fn root_inode(&self) -> Arc<dyn Inode> {
        Arc::clone(self.root_fs().metadata().root_inode.as_ref().unwrap())
    }
    pub fn root_fs(&self) -> Arc<dyn FileSystem> {
        Arc::clone(self.fs_manager.lock().get("/").unwrap())
    }

    pub fn mount(
        &self,
        mount_point: &str, // must be absolute path
        dev_name: &str,
        device: FsDevice,
        fstype: FileSystemType,
        flags: StatFlags,
    ) -> GeneralResult<Arc<dyn FileSystem>> {
        // find covered inode, fa inode, etc
        let mut is_dummy_vfat = false;
        let mount_point_fa = path::get_parent_dir(mount_point);
        let mount_point_name = path::get_name(mount_point);
        let fa_inode;
        let covered_inode;
        let covered_fs;
        let fa_ino;
        if let Some(mount_point_fa) = mount_point_fa {
            (fa_inode, _) = <dyn Inode>::lookup_from_root(&mount_point_fa)?;
            if fa_inode.is_none() {
                log::warn!(
                    "[mount] parent inode doesn't exist, name {}",
                    mount_point_fa
                );
                return Err(Errno::EEXIST);
            }
            let fa_inode_unwrap = Arc::clone(fa_inode.as_ref().unwrap());
            fa_ino = fa_inode_unwrap.metadata().ino;
            let maybe_covered_inode = fa_inode_unwrap.lookup(mount_point_name)?;
            covered_fs = self.fs_manager.lock().get(mount_point).cloned();
            if maybe_covered_inode.is_none() {
                return Err(Errno::EEXIST);
            }
            covered_inode = Some(maybe_covered_inode.unwrap());
        } else {
            fa_inode = None;
            covered_inode = None;
            covered_fs = None;
            fa_ino = 0;
        }
        let key = HashKey::new(fa_ino, mount_point_name.to_string());
        log::debug!("[mount] mount point {}, hash key {:?}", mount_point, key);
        // create fs
        let fs: Arc<dyn FileSystem> = match fstype {
            FileSystemType::VFAT => {
                let ret = FAT32FileSystem::new(
                    //wyz:wait to add fat32
                    Some(Arc::clone(device.block_device().unwrap())),
                    mount_point,
                    dev_name,
                    fstype,
                    flags,
                    fa_inode,
                    covered_inode,
                    covered_fs,
                )?;
                Arc::new(ret)
            }
            FileSystemType::DummyVFAT => {
                is_dummy_vfat = true;
                let ret = FAT32FileSystem::new(
                    None,
                    mount_point,
                    dev_name,
                    fstype,
                    flags,
                    fa_inode,
                    covered_inode,
                    covered_fs,
                )?;
                Arc::new(ret)
            }
        };
        // insert root inode into inode cache
        let meta = fs.metadata();
        if !is_dummy_vfat {
            INODE_CACHE.insert(key.clone(), Arc::clone(meta.root_inode.as_ref().unwrap()));
            log::debug!(
                "[mount] mount point {} inode ino {}",
                mount_point,
                meta.root_inode.as_ref().unwrap().metadata().ino
            );
        }
        // insert file system into file system manager
        let mut fs_locked = self.fs_manager.lock();
        fs_locked.insert(mount_point.to_string(), Arc::clone(&fs));

        Ok(fs)
    }

    /// TODO: change into async
    pub fn unmount(&self, mount_point: &str) -> GeneralResult<()> {
        let fs = self.fs_manager.lock().get(mount_point).cloned();

        if fs.is_none() {
            return Err(Errno::EEXIST);
        }
        let fs = fs.unwrap();
        let mut is_none = false;
        if let FileSystemType::DummyVFAT = fs.metadata().file_system_type {
            is_none = true;
        }

        // TODO: this may lead to dead lock since the async function may try to
        // hold a sleeplock.
        // let fs_moved = fs.clone();
        // block_on(async move {wyz: have to remove
        //     if fs_moved.sync_fs().await.is_err() {
        //         log::error!(
        //             "[umount] fs {} must have already been umounted",
        //             fs_moved.metadata().mount_point
        //         );
        //     }
        // });

        let meta = fs.metadata();
        // remove root inode from inode cache
        if !is_none {
            let fa_ino = {
                if let Some(some_fa_inode) = meta.parent_inode.as_ref() {
                    // remove root inode from fa
                    some_fa_inode.remove_child(Arc::clone(meta.root_inode.as_ref().unwrap()))?;
                    some_fa_inode.metadata().ino
                } else {
                    0
                }
            };
            let mount_point_name = path::get_name(mount_point);
            let key = HashKey::new(fa_ino, mount_point_name.to_string());
            INODE_CACHE.remove(&key);
            if meta.covered_root_inode.is_some() {
                INODE_CACHE.insert(key, Arc::clone(meta.covered_root_inode.as_ref().unwrap()));
            }
        }

        // remove file system from file system manager
        self.fs_manager.lock().remove(mount_point);

        if meta.covered_file_system.is_some() {
            self.fs_manager.lock().insert(
                mount_point.to_string(),
                meta.covered_file_system.as_ref().unwrap().clone(),
            );
        }
        Ok(())
        // fs will be dropped automatically because Arc = 0
    }
