#[allow(clippy::too_many_arguments)]
impl FAT32FileSystem {
    pub fn new(
        block_device: Option<Arc<dyn BlockDevice>>,
        mount_point: &str,
        dev_name: &str,
        fstype: FileSystemType,
        flags: StatFlags,
        fa_inode: Option<Arc<dyn Inode>>,
        covered_inode: Option<Arc<dyn Inode>>,
        covered_fs: Option<Arc<dyn FileSystem>>,
    ) -> GeneralResult<Self> {
        let mut bs_data: [u8; SECTOR_SIZE] = [0; SECTOR_SIZE];
        let block_is_none = block_device.is_none();
        if !block_is_none {
            let unwrap_block_device = block_device.clone().unwrap();
            unwrap_block_device.read_block(BOOT_SECTOR_ID, &mut bs_data[..]);
        }

        let raw_bs: BIOSParameterBlock = BIOSParameterBlock::new(&bs_data);
        let info = if !block_is_none {
            Arc::new(FAT32Info::new(raw_bs))
        } else {
            Arc::new(FAT32Info {
                bootsector_block_id: 0,
                filesystem_info_sector_id: 0,
                start_sector_of_fat: 0,
                total_sectors_in_fat: 0,
                number_of_fats: 0,
                start_sector_of_data: 0,
                sector_per_cluster: 0,
                total_sector_count: 0,
                total_cluster_count: 0,
                root_cluster_id: 0,
            })
        };
        let root_inode = if !block_is_none {
            if !raw_bs.validate() {
                return Err(Errno::EINVAL);
            }
            let fat = Arc::new(FileAllocationTable::new(
                block_device.unwrap(),
                Arc::clone(&info),
            ));
            let raw_root_inode = FAT32Inode::new_root(
                Arc::clone(&fat),
                Option::clone(&fa_inode),
                mount_point,
                info.root_cluster_id,
            );
            Some(Arc::new(raw_root_inode) as Arc<dyn Inode>)
        } else {
            None
        };
        let meta = FileSystemMetadata {
            device_name: dev_name.to_string(),
            mount_path: mount_point.to_string(),
            file_system_type: fstype,
            file_system_flags: flags,
            root_inode,
            parent_inode: fa_inode,
            covered_root_inode: covered_inode,
            covered_file_system: covered_fs,
            dirty_inodes: Vec::new(),
        };
        let ret = Self { meta };
        Ok(ret)
    }
}

