impl FAT32Inode {
    pub fn new_root(
        fat: Arc<FileAllocationTable>,
        fa_inode: Option<Arc<dyn Inode>>,
        path: &str,
        first_cluster: usize,
    ) -> Self {
        let mode = FileType::FileDIR;
        let meta = InodeMeta::new(fa_inode, path, mode, 0, None);
        let file = FAT32File::new(Arc::clone(&fat), first_cluster, None);
        Self {
            metadata: Some(meta),
            fat: Arc::clone(&fat),
            file: Mutex::new(file),
        }
    }

    pub fn from_dentry(
        fat: Arc<FileAllocationTable>,
        fa_inode: Option<Arc<dyn Inode>>,
        dentry: &FAT32Direntry,
    ) -> Self {
        let mode = if (dentry.attributes & ATTR_DIRECTORY) == ATTR_DIRECTORY {
            FileType::FileDIR
        } else {
            FileType::FileREG
        };
        let meta = InodeMeta::new(
            fa_inode,
            &dentry.get_filename(),
            mode,
            if mode == FileType::FileREG {
                dentry.file_size as usize
            } else {
                0
            },
            None,
        );
        {
            let mut inner_lock = meta.inner.lock();
            inner_lock.last_atime = unix_time_to_timespec(FAT32_to_unix_time(dentry.access_time));
            inner_lock.last_stime = unix_time_to_timespec(FAT32_to_unix_time(dentry.creation_time));
            inner_lock.last_mtime = unix_time_to_timespec(FAT32_to_unix_time(dentry.write_time));
        }
        let file = FAT32File::new(
            Arc::clone(&fat),
            dentry.first_cluster as usize,
            if mode == FileType::FileREG {
                Some(dentry.file_size as usize)
            } else {
                None
            },
        );
        Self {
            metadata: Some(meta),
            fat: Arc::clone(&fat),
            file: Mutex::new(file),
        }
    }

    pub fn new(
        fat: Arc<FileAllocationTable>,
        fa_inode: Arc<dyn Inode>,
        name: &str,
        mode: FileType,
    ) -> Self {
        let parent_path = fa_inode.metadata().file_path.clone();
        let path = path::merge(&parent_path, name);
        log::debug!(
            "[Fat32Indoe::new] parent_path: {}, path: {}",
            parent_path,
            path
        );
        let meta = InodeMeta::new(Some(fa_inode), &path, mode, 0, None);
        let file = FAT32File::new(
            Arc::clone(&fat),
            0,
            if mode == FileType::FileREG {
                Some(0)
            } else {
                None
            },
        );
        Self {
            metadata: Some(meta),
            fat: Arc::clone(&fat),
            file: Mutex::new(file),
        }
    }
}

