        while let Some(dentry) = FAT32Direntry::dentry_read(&mut dentry_content) {
            let fname = dentry.get_filename();
            debug!(
                "from dir: /{}  find children: {}  target children: {}",
                meta.file_name,
                dentry.get_filename(),
                target_children
            );
            if fname == "." || fname == ".." {
                continue;
            }
            let inode = FAT32Inode::from_dentry(Arc::clone(&fat), Some(Arc::clone(&this)), &dentry);
            let inode_rc: Arc<dyn Inode> = Arc::new(inode);
            inode_rc.try_create_page_cache();
            //insert children
            meta_inner
                .children_inodes
                .insert(fname.clone(), Arc::clone(&inode_rc));
            //insert InodeCache
            let key = HashKey::new(meta.ino, fname.clone());
            INODE_CACHE.insert(key, inode_rc);
            meta_inner.state = InodeState::SyncedBoth;
            if (fname == target_children) {
                //abort due to finding the target children
                debug!("find target children: {}", target_children);
                meta_inner.is_all_load = false;
                break;
            }
        }
        meta_inner.lookup_hint = dentry_content.offset;
        if let Some(dentry) = FAT32Direntry::dentry_read(&mut dentry_content) {
            //avoid the target_inode is the last one
            meta_inner.is_all_load = false;
        }
    }
}

