#[derive(Clone, Copy)]
struct FATSectorBuffer {
    sector_number: usize,
    data: [u32; FATENTRY_PER_SECTOR],
    state: FAT32SectorBufferState,
}

impl Default for FATSectorBuffer {
    fn default() -> Self {
        Self {
            sector_number: usize::default(),
            data: [u32::default(); FATENTRY_PER_SECTOR],
            state: FAT32SectorBufferState::default(),
        }
    }
}

impl FATSectorBuffer {
    pub fn sync(&mut self, block_device: Arc<dyn BlockDevice>, fatinfo: Arc<FAT32Info>) {
        if self.state == FAT32SectorBufferState::Dirty {
            for i in 0..fatinfo.number_of_fats {
                unsafe {
                    block_device.write_block(
                        fatinfo.start_sector_of_fat
                            + i * fatinfo.total_sectors_in_fat
                            + self.sector_number,
                        core::slice::from_raw_parts(
                            self.data.as_ptr() as *const u8,
                            self.data.len() * core::mem::size_of::<u32>(),
                        ),
                    );
                }
            }
            self.state = FAT32SectorBufferState::Allocated;
        }
    }

    pub fn free(&mut self, block_device: Arc<dyn BlockDevice>, fatinfo: Arc<FAT32Info>) {
        self.sync(Arc::clone(&block_device), Arc::clone(&fatinfo));
        self.state = FAT32SectorBufferState::NotAllocated;
    }

    pub fn init(
        &mut self,
        block_device: Arc<dyn BlockDevice>,
        fatinfo: Arc<FAT32Info>,
        sector_no: usize,
    ) {
        self.free(Arc::clone(&block_device), Arc::clone(&fatinfo));
        self.state = FAT32SectorBufferState::Allocated;
        self.sector_number = sector_no;
        unsafe {
            block_device.read_block(
                fatinfo.start_sector_of_fat + self.sector_number,
                core::slice::from_raw_parts_mut(
                    self.data.as_mut_ptr() as *mut u8,
                    self.data.len() * core::mem::size_of::<u32>(),
                ),
            );
        }
    }

    pub fn read(&self, offset: usize) -> Option<u32> {
        if self.state == FAT32SectorBufferState::NotAllocated || offset >= FATENTRY_PER_SECTOR {
            None
        } else {
            Some(self.data[offset] & 0x0FFFFFFF)
        }
    }

    pub fn write(&mut self, offset: usize, val: u32) -> Option<()> {
        if self.state == FAT32SectorBufferState::NotAllocated || offset >= FATENTRY_PER_SECTOR {
            None
        } else {
            self.data[offset] = (self.data[offset] & 0xF0000000) | (val & 0x0FFFFFFF);
            self.state = FAT32SectorBufferState::Dirty;
            Some(())
        }
    }
}
pub struct FATMeta {
    // The number of free clusters in the file allocation table
    free_count: usize,
    // A hint for the next free cluster in the file allocation table
    fat_hint: usize,
}

pub struct FileAllocationTable {
    // The block device where the file allocation table is stored
    pub block_device: Arc<dyn BlockDevice>,
    // Information about the FAT32 file system
    pub fat_info: Arc<FAT32Info>,
    // Cache for the file allocation table
    fat_cache: Mutex<FATBufferCache>,
    // Metadata for the file allocation table
    fat_meta: Arc<Mutex<FATMeta>>,
}

impl FileAllocationTable {
    pub fn new(block_device: Arc<dyn BlockDevice>, info: Arc<FAT32Info>) -> Self {
        let mut fsinfo_data: [u8; 512] = [0; 512];
        block_device.read_block(info.filesystem_info_sector_id, &mut fsinfo_data);
        let fsinfo_raw = FileSystemInfo::new(&fsinfo_data);
        if !fsinfo_raw.is_valid() {
            debug!("fsinfo magic number wrong!");
        }
        let free_count = fsinfo_raw.free_clusters_count as usize;
        let nxt_free = fsinfo_raw.next_free_cluster as usize;
        let ret = Self {
            block_device: Arc::clone(&block_device),
            fat_info: Arc::clone(&info),
            fat_cache: Mutex::new(FATBufferCache::new(
                Arc::clone(&block_device),
                Arc::clone(&info),
            )),
            fat_meta: Arc::new(Mutex::new(FATMeta {
                free_count,
                fat_hint: nxt_free,
            })),
        };
        ret.free_stat();
        ret
    }
    fn free_stat(&self) {
        let mut fatmeta_locked = self.fat_meta.lock();
        if fatmeta_locked.free_count == (FSI_NOT_AVAILABLE as usize)
            || fatmeta_locked.fat_hint == (FSI_NOT_AVAILABLE as usize)
        {
            fatmeta_locked.free_count = 0;
            fatmeta_locked.fat_hint = 0; //wyz:为什么不是2
            for i in 0..self.fat_info.total_cluster_count {
                let cluster_id = i + 2;
                let fatentry = self.fat_read(cluster_id).unwrap() & 0x0FFFFFFF;
                if fatentry == 0 {
                    fatmeta_locked.free_count += 1;
                } else {
                    fatmeta_locked.fat_hint = cluster_id;
                }
            }
        }
    }

    pub fn fat_read(&self, cluster_id: usize) -> Option<u32> {
        self.fat_cache.lock().fat_read(cluster_id)
    }

    pub fn fat_write(&self, cluster_id: usize, val: u32) -> Option<()> {
        self.fat_cache.lock().fat_write(cluster_id, val)
    }

    #[allow(unused)]
    pub fn fat_sync(&self) {
        self.fat_cache.lock().sync_all_buffers();
    }

    fn get_free_cluster(&self) -> Option<usize> {
        let mut fatmeta_locked = self.fat_meta.lock();
        fatmeta_locked.fat_hint += 1; //move hint to next number
        if (fatmeta_locked.fat_hint < self.fat_info.total_cluster_count) {
            //if below cluster_count，then the cluster that hint point to must be free
            fatmeta_locked.free_count -= 1;
            return Some(fatmeta_locked.fat_hint);
        }
        //else search from ( hint % cluster_count ) to cluster_count
        for i in fatmeta_locked.fat_hint % self.fat_info.total_cluster_count
            ..self.fat_info.total_cluster_count
        {
            if i == 0 || i == 1 {
                continue;
            }
            let fatentry = self.fat_read(i).unwrap() & 0x0FFFFFFF;
            if fatentry == 0 {
                //the cluster is free
                fatmeta_locked.free_count -= 1;
                return Some(i);
            }
        }
        None
    }

    pub fn alloc_cluster(&self, prev: Option<usize>) -> Option<usize> {
        if let Some(ret) = self.get_free_cluster() {
            if let Some(pre) = prev {
                if self.fat_read(pre).unwrap() < 0x0FFFFFF8 {
                    debug!("write data at non fat link tail!");
                }
                self.fat_write(pre, ret as u32);
            }
            self.fat_write(ret, 0x0FFFFFFF);
            Some(ret)
        } else {
            None
        }
    }

    pub fn cluster_free(&self, cluster_id: usize, prev: Option<usize>) -> Option<()> {
        if let Some(pre) = prev {
            if self.fat_read(pre).unwrap() as usize != cluster_id {
                debug!("not a right pre!");
                return None;
            }
            self.fat_write(pre, 0x0FFFFFFF);
        }
        self.fat_write(cluster_id, 0);
        let mut fatmeta_locked = self.fat_meta.lock();
        fatmeta_locked.free_count += 1;
        Some(())
    }
}

