pub const MAX_SIGNUM: u32 = 64;
#[derive(Debug, Clone, Copy, Eq, PartialEq)]
#[allow(unused)]
#[allow(non_camel_case_types)]
#[allow(clippy::upper_case_acronyms)]
#[repr(u32)]
pub enum SignalFlags {
    EMPTY = 0,
    SIGINT = 2,
    SIGILL = 4,
    SIGABRT = 6,
    SIGFPE = 8,
    SIGKILL = 9,
    SIGUSR1 = 10,
    SIGSEGV = 11,
    SIGCHLD = 17,
}

bitflags! {
    #[derive(PartialEq, Eq, Debug, Copy, Clone)]
    pub struct SigMask: usize {
        const SIGINT    = 1 << 1;
        const SIGILL    = 1 << 3;
        const SIGABRT   = 1 << 5;
        const SIGFPE    = 1 << 7;
        const SIGKILL   = 1 << 8;
        const SIGUSR1   = 1 << 9;
        const SIGSEGV   = 1 << 10;
        const SIGCHLD   = 1 << 16;
    }
}

pub type SigSet = SigMask;

impl SigMask {
    #[allow(unused)]
    pub fn add(&mut self, signum: u32) {
        if signum >= MAX_SIGNUM {
            panic!(
                "[Kernel] process/signals/signal_flags.rs: invalid signum: {}",
                signum
            );
        }
        *self |= SigMask::from_bits_truncate(1 << (signum - 1));
    }

    pub fn sub(&mut self, signum: u32) {
        if signum >= MAX_SIGNUM {
            panic!(
                "[Kernel] process/signals/sigal_flags.rs: invalid signum: {}",
                signum
            );
        }
        *self -= SigMask::from_bits_truncate(1 << (signum - 1));
    }

    #[allow(unused)]
    pub fn add_other(&mut self, other: SigMask) {
        *self |= other;
    }

    #[allow(unused)]
    pub fn sub_other(&mut self, other: SigMask) {
        *self -= other;
    }

    pub fn if_contains(&self, signum: u32) -> bool {
        self.contains(SigMask::from_bits_truncate(1 << (signum - 1)))
    }

    #[allow(unused)]
    pub fn fetch(&mut self) -> Option<u32> {
        let mut signum = 1;
        while signum < MAX_SIGNUM {
            if self.if_contains(signum) {
                return Some(signum);
            }
            signum += 1;
        }
        None
    }
}

