        &mut self.env
    }

    pub fn env(&self) -> &EnvContext {
        &self.env
    }

    /// Whether there is no user task now(i.e. kernel thread is running)
    pub fn is_idle(&self) -> bool {
        self.user_task_ctx.is_none()
    }
}

