    future::Future,
    pin::Pin,
    task::{ready, Context, Poll, Waker},
    time::Duration,
};

struct Sleeper {
    expired_time: Duration,
    waker: Option<Waker>,
}

impl PartialEq for Sleeper {
    fn eq(&self, other: &Self) -> bool {
        self.expired_time == other.expired_time
    }
}

impl PartialOrd for Sleeper {
    fn partial_cmp(&self, other: &Self) -> Option<core::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Eq for Sleeper {}

impl Ord for Sleeper {
    fn cmp(&self, other: &Self) -> core::cmp::Ordering {
        self.expired_time.cmp(&other.expired_time)
    }
}

pub struct SleepQueue {
    sleepers: SpinNoIrqLock<Option<BinaryHeap<Reverse<Sleeper>>>>,
}

impl SleepQueue {
    const fn new() -> Self {
        Self {
            sleepers: SpinNoIrqLock::new(None),
        }
    }

    pub fn init(&self) {
        *self.sleepers.lock() = Some(BinaryHeap::new());
    }

    fn one_more(&self, sleeper: Sleeper) {
        self.sleepers
            .lock()
            .as_mut()
            .unwrap()
            .push(Reverse(sleeper));
    }
}

pub static SLEEP_QUEUE: SleepQueue = SleepQueue::new();

pub enum TimeoutTaskOutput<T> {
    Timeout,
    Ok(T),
}

pub struct TimeoutTaskFuture<F: Future + Send + 'static> {
    expired_time: Duration,
    task_future: F,
    has_added_to_queue: bool,
}

impl<F: Future + Send + 'static> TimeoutTaskFuture<F> {
    pub fn new(duration: Duration, task_future: F) -> Self {
        Self {
            expired_time: get_time_duration() + duration,
            task_future,
            has_added_to_queue: false,
        }
    }
}

impl<F: Future + Send + 'static> Future for TimeoutTaskFuture<F> {
    type Output = TimeoutTaskOutput<F::Output>;
    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        log::trace!("[TimeoutTaskFuture::poll] enter");
        let this = unsafe { self.get_unchecked_mut() };
        let ret = unsafe { Pin::new_unchecked(&mut this.task_future).poll(cx) };
        if ret.is_pending() {
            if get_time_duration() >= this.expired_time {
                Poll::Ready(TimeoutTaskOutput::Timeout)
            } else {
                if !this.has_added_to_queue {
                    let sleeper = Sleeper {
                        expired_time: this.expired_time,
                        waker: Some(cx.waker().clone()),
                    };
                    SLEEP_QUEUE.one_more(sleeper);
                    this.has_added_to_queue = true;
                    log::trace!("[TimeoutTaskFuture::poll] add timer");
                }

                log::trace!("[TimeoutTaskFuture::poll] still not ready");

                // If single core
                #[cfg(not(feature = "kernel_interrupt"))]
                cx.waker().wake_by_ref();

                Poll::Pending
            }
        } else {
            Poll::Ready(TimeoutTaskOutput::Ok(ready!(ret)))
        }
    }
}

struct IdleFuture;

impl Future for IdleFuture {
    type Output = ();
    fn poll(self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<Self::Output> {
        Poll::Pending
    }
}

#[allow(unused)]
pub async fn ksleep(duration: Duration) {
    TimeoutTaskFuture::new(duration, IdleFuture {}).await;
}

pub fn handle_timeout_events() {
    // debug!("[handle_timeout_events]: start..., sepc {:#x}", sepc::read());
    let current_time = get_time_duration();
    let mut inner = SLEEP_QUEUE.sleepers.lock();
    let timers = inner.as_mut().unwrap();
    // TODO: should we use SleepLock instead of SpinLock? It seems that the locking time may be a little long.
    while let Some(timer) = timers.peek() {
        if current_time >= timer.0.expired_time {
            trace!(
                "[handle_timeout_events] find a timeout timer, current ts: {:?}, expired ts: {:?}",
                current_time,
                timer.0.expired_time
            );
            let mut timer = timers.pop().unwrap();
            timer.0.waker.take().unwrap().wake();
        } else {
            break;
        }
    }
}

