/// `Dirent` 结构体表示一个目录项。
///
/// # 字段
///
/// * `d_ino` - 64位的 inode 编号。
/// * `d_off` - 到下一个 dirent 的64位偏移量。
/// * `d_reclen` - 这个 dirent 的大小。
/// * `d_type` - 文件类型。
/// * `d_name` - 文件名。
#[derive(Debug)]
#[repr(C)]
#[derive(Copy, Clone)]
pub struct Dirent {
    pub d_ino: usize,
    pub d_off: usize,
    pub d_reclen: u16,
    pub d_type: u8,
    pub d_name: [u8; 256],
}
pub const DIRENT_SIZE: u16 = size_of::<Dirent>() as u16;
pub const MAX_NAME_LEN: usize = 256;

impl Dirent {
    /// 获取从指定索引开始的目录项列表。
    ///
    /// # 参数
    ///
    /// * `inode` - 一个实现了 `Inode` trait 的对象的 Arc 指针。
    /// * `start_index` - 起始索引，从此索引开始获取目录项。
    ///
    /// # 返回
    ///
    /// 返回一个包含 `Dirent` 对象的 Vec。
    pub fn get_dirents(inode: Arc<dyn Inode>, start_index: usize) -> Vec<Self> {
        debug!("[dirent] start_index: {}", start_index);
        let inode_meta = inode.metadata();
        let child = inode_meta.inner.lock().children_inodes.clone();
        let mut dirents: Vec<Dirent> = Vec::new();
        for (i, (_, value)) in child.into_iter().enumerate() {
            if i < start_index {
                continue;
            }
            let mut dirent = Dirent {
                d_ino: value.metadata().ino,
                d_off: 0,
                d_reclen: 0,
                d_type: value.metadata().file_type as u8,
                d_name: string_to_array(value.metadata().file_name.clone()),
            };
            dirent.d_reclen =
                (DIRENT_SIZE as usize - (MAX_NAME_LEN - array_str_len(&dirent.d_name))) as u16;
            debug!(
                "[dirent] i is: {}, d_name is: {}, d_ino is: {}, d_type: {:?}, d_reclen: {}",
                i,
                value.metadata().file_name.clone(),
                value.metadata().ino,
                value.metadata().file_type,
                dirent.d_reclen
            );
            dirents.push(dirent);
        }
        dirents
    }
}

