pub struct Stdin {
    metadata: FileMetadata,
}
pub struct Stdout {
    metadata: FileMetadata,
}
pub struct Stderr {
    metadata: FileMetadata,
}

impl Stdin {
    pub fn new() -> Self {
        Self {
            metadata: FileMetadata::new(FileType::FileCHR, None),
        }
    }
}
impl File for Stdin {
    fn metadata(&self) -> &FileMetadata {
        &self.metadata
    }
    fn read<'a>(&'a self, buf: &'a mut [u8], _flags: OpenFlags) -> AsyscallResult {
        Box::pin(async move {
            let mut c: isize;
            let mut i = 0;
            loop {
                c = crate::sbi::console_getchar();
                if c == 0 {
                    continue;
                } else {
                    let ch = c as u8;
                    buf[i] = ch;
                    i += 1;
                    if i >= buf.len() {
                        break;
                    }
                }
            }
            Ok(i as isize) // 返回读取的字节数
        })
    }
    fn write<'a>(&'a self, _buf: &'a [u8], _flags: OpenFlags) -> AsyscallResult {
        Box::pin(async move { Ok(1) })
    }
}

impl Stdout {
    pub fn new() -> Self {
        Self {
            metadata: FileMetadata::new(FileType::FileCHR, None),
        }
    }
}

impl File for Stdout {
    fn metadata(&self) -> &FileMetadata {
        &self.metadata
    }
    fn read<'a>(&'a self, _buf: &'a mut [u8], _flags: OpenFlags) -> AsyscallResult {
        Box::pin(async move { Ok(1) })
    }
    fn write<'a>(&'a self, buf: &'a [u8], _flags: OpenFlags) -> AsyscallResult {
        let mut i = 0;
        Box::pin(async move {
            for &c in buf {
                crate::sbi::console_putchar(c as i32);
                i += 1;
            }
            Ok(i as isize)
        })
    }
}

impl Stderr {
    pub fn new() -> Self {
