use super::{fat::FileAllocationTable, SECTOR_SIZE};
use alloc::{sync::Arc, vec::Vec};
use core::cmp::{max, min};

pub struct FAT32File {
    pub fat: Arc<FileAllocationTable>,
    clusters: Vec<usize>,
    size: Option<usize>,
}

impl FAT32File {
    pub fn new(fat: Arc<FileAllocationTable>, first_cluster: usize, size: Option<usize>) -> Self {
        let mut clusters_vec = Vec::new();
        if first_cluster != 0 {
            clusters_vec.push(first_cluster);
        }
        Self {
            fat: Arc::clone(&fat),
            clusters: clusters_vec,
            size,
        }
    }

    #[allow(unused)]
    pub fn first_cluster(&self) -> u32 {
        if !self.clusters.is_empty() {
            self.clusters[0] as u32
        } else {
            0
        }
    }

    fn get_clusters(&mut self) {
        if !self.clusters.is_empty() {
            loop {
                let nxt_cluster = self.fat.fat_read(*self.clusters.last().unwrap()).unwrap();
                if nxt_cluster >= 0x0FFFFFF8 {
                    break;
                }
                self.clusters.push(nxt_cluster as usize);
            }
        }
        if self.size.is_none() {
            self.size =
                Some(self.clusters.len() * SECTOR_SIZE * self.fat.fat_info.sector_per_cluster);
        }
    }

    pub fn modify_size(&mut self, delta: isize) -> usize {
        self.get_clusters();
        if delta < 0 && (self.size.unwrap() as isize) + delta >= 0 {
            let new_sz = ((self.size.unwrap() as isize) + delta) as usize;
            let cluster_count = (new_sz + self.fat.fat_info.sector_per_cluster * SECTOR_SIZE - 1)
                / (self.fat.fat_info.sector_per_cluster * SECTOR_SIZE);
            while self.clusters.len() > cluster_count {
                let end0 = self.clusters.pop().unwrap();
                if !self.clusters.is_empty() {
                    let end1 = *self.clusters.last().unwrap();
                    self.fat.cluster_free(end0, Some(end1));
                } else {
                    self.fat.cluster_free(end0, None);
                }
            }
            self.size = Some(new_sz);
        } else if delta > 0 {
            let new_sz = self.size.unwrap() + (delta as usize);
            let cluster_count = (new_sz + self.fat.fat_info.sector_per_cluster * SECTOR_SIZE - 1)
                / (self.fat.fat_info.sector_per_cluster * SECTOR_SIZE);
            while self.clusters.len() < cluster_count {
                let new_cluster = if !self.clusters.is_empty() {
                    self.fat
                        .alloc_cluster(Some(*self.clusters.last().unwrap()))
                        .unwrap()
                } else {
                    self.fat.alloc_cluster(None).unwrap()
                };
                self.clusters.push(new_cluster);
                self.clusters.push(new_cluster);
            }
            self.size = Some(new_sz);
        }
        self.size.unwrap()
    }

    pub fn read(&mut self, data: &mut [u8], offset: usize) -> usize {
        self.get_clusters();
        let st = min(offset, self.size.unwrap());
        let ed = min(offset + data.len(), self.size.unwrap());
        let ret = ed - st;
        let st_cluster = st / (self.fat.fat_info.sector_per_cluster * SECTOR_SIZE);
        let ed_cluster = (ed + self.fat.fat_info.sector_per_cluster * SECTOR_SIZE - 1)
            / (self.fat.fat_info.sector_per_cluster * SECTOR_SIZE);
        for cseq in st_cluster..ed_cluster {
            let cluster_id = self.clusters[cseq];
            let sector_id = self.fat.fat_info.cid_to_sid(cluster_id).unwrap();
            for j in 0..self.fat.fat_info.sector_per_cluster {
                let off = cseq * self.fat.fat_info.sector_per_cluster + j; //wyz:+j近似于移动读指针
                let sector_st = off * SECTOR_SIZE;
                let sector_ed = sector_st + SECTOR_SIZE;
                if sector_ed <= st || sector_st >= ed {
                    continue;
                }
                let cur_st = max(sector_st, st);
                let cur_ed = min(sector_ed, ed);
                let mut tmp_data: [u8; SECTOR_SIZE] = [0; SECTOR_SIZE];
                self.fat
                    .block_device
                    .read_block(sector_id + j, &mut tmp_data[..]); //wyz:为什么不直接搞个读指针，省得用tmp
                data[(cur_st - st)..(cur_ed - st)]
                    .copy_from_slice(&tmp_data[(cur_st - sector_st)..(cur_ed - sector_st)]);
            }
        }
        ret
    }

    pub fn write(&mut self, data: &[u8], offset: usize) -> usize {
        self.get_clusters();
        let st = min(offset, self.size.unwrap());
        let ed = offset + data.len();
        if self.size.unwrap() < ed {
            self.modify_size((ed - self.size.unwrap()) as isize);
        }
        let ret = ed - st;
        let st_cluster = st / (self.fat.fat_info.sector_per_cluster * SECTOR_SIZE);
        let ed_cluster = (ed + self.fat.fat_info.sector_per_cluster * SECTOR_SIZE - 1)
            / (self.fat.fat_info.sector_per_cluster * SECTOR_SIZE);
        for cseq in st_cluster..ed_cluster {
            let cluster_id = self.clusters[cseq];
            let sector_id = self.fat.fat_info.cid_to_sid(cluster_id).unwrap();
            for j in 0..self.fat.fat_info.sector_per_cluster {
                let off = cseq * self.fat.fat_info.sector_per_cluster + j;
                let sector_st = off * SECTOR_SIZE;
                let sector_ed = sector_st + SECTOR_SIZE;
                if sector_ed <= st || sector_st >= ed {
                    continue;
                }
                let cur_st = max(sector_st, st);
                let cur_ed = min(sector_ed, ed);
                let mut tmp_data: [u8; SECTOR_SIZE] = [0; SECTOR_SIZE];
                if cur_st != sector_st || cur_ed != sector_ed {
                    self.fat
                        .block_device
                        .read_block(sector_id + j, &mut tmp_data[..]);
                }
                tmp_data[cur_st - sector_st..cur_ed - sector_st]
                    .copy_from_slice(&data[cur_st - st..cur_ed - st]);
                self.fat
                    .block_device
                    .write_block(sector_id + j, &tmp_data[..]);
            }
        }
        ret
    }
}

