const ATTR_READ_ONLY: u8 = 0x01;
const ATTR_HIDDEN: u8 = 0x02;
const ATTR_SYSTEM: u8 = 0x04;
const ATTR_VOLUME_ID: u8 = 0x08;
pub const ATTR_DIRECTORY: u8 = 0x10;
const ATTR_ARCHIVE: u8 = 0x20;
const ATTR_LONG_NAME: u8 = 0x0F;
const DENTRY_SIZE: usize = 0x20;

pub struct FAT32DentryData<'a> {
    file: &'a mut FAT32File,
    pub offset: usize,
}

impl<'a> FAT32DentryData<'a> {
    pub fn new(file: &'a mut FAT32File, offset: usize) -> Self {
        Self { file, offset }
    }

    #[allow(unused)]
    pub fn seek(&mut self, offset: usize) {
        self.offset = offset
    }
}
pub trait DentryDataReader {
    fn dentry_read(&mut self, data: &mut [u8]) -> usize;
}

pub trait DentryDataWriter: Send + Sync {
    fn dentry_write(&mut self, data: &[u8]);
}

impl DentryDataReader for FAT32DentryData<'_> {
    fn dentry_read(&mut self, data: &mut [u8]) -> usize {
        let ret = self.file.read(data, self.offset);
        self.offset += ret;
        ret
    }
}

impl DentryDataWriter for FAT32DentryData<'_> {
    fn dentry_write(&mut self, data: &[u8]) {
        let ret = self.file.write(data, self.offset);
        self.offset += ret;
    }
}

pub struct FAT32Direntry {
    pub long_name: [u16; LNAME_MAXLEN],
    pub short_name: [u8; SNAME_LEN],
    pub attributes: u8,
    pub creation_time: FAT32Timestamp,
    pub write_time: FAT32Timestamp,
    pub access_time: FAT32Timestamp,
    pub first_cluster: u32,
    pub file_size: u32,
}

impl FAT32Direntry {
    #[allow(unused)]
    fn dentry_write(&self, writer: &mut dyn DentryDataWriter) {
        let mut lname_len = 0;
        while lname_len < LNAME_MAXLEN && self.long_name[lname_len] != 0 {
            lname_len += 1;
        }
        let mut write_buf: [u8; DENTRY_SIZE] = [0; DENTRY_SIZE];
        let ldir_count = (lname_len + 12) / 13;
        let chksum = shortname_checksum(&self.short_name[..]);

        macro_rules! lsb16 {
            ($data_idx: expr, $data: expr) => {
                write_buf[$data_idx] = (($data & 0xFF) as u8);
                write_buf[$data_idx + 1] = ((($data >> 8) & 0xFF) as u8);
            };
        }

        macro_rules! s_lname {
            ($data_idx: expr, $lname_idx: expr) => {
                lsb16!($data_idx, {
                    if $lname_idx == lname_len {
                        0
                    } else if $lname_idx > lname_len {
                        0xFFFF
                    } else {
                        self.long_name[$lname_idx]
                    }
                });
            };
        }

        for ldir_id in (1..=ldir_count).rev() {
            let lname_offset = (ldir_id - 1) * 13;
            s_lname!(1, lname_offset);
            s_lname!(3, lname_offset + 1);
            s_lname!(5, lname_offset + 2);
            s_lname!(7, lname_offset + 3);
            s_lname!(9, lname_offset + 4);
            s_lname!(14, lname_offset + 5);
            s_lname!(16, lname_offset + 6);
            s_lname!(18, lname_offset + 7);
            s_lname!(20, lname_offset + 8);
            s_lname!(22, lname_offset + 9);
            s_lname!(24, lname_offset + 10);
            s_lname!(28, lname_offset + 11);
            s_lname!(30, lname_offset + 12);

            write_buf[0] = (ldir_id as u8) | {
                if ldir_id == lname_len {
                    0x40
                } else {
                    0
                }
            };
            write_buf[11] = ATTR_LONG_NAME;
            write_buf[12] = 0;
            write_buf[13] = chksum;
            write_buf[26] = 0;
            write_buf[27] = 0;
            writer.dentry_write(&write_buf[..]);
        }
        write_buf[..SNAME_LEN].copy_from_slice(&self.short_name[..SNAME_LEN]);
        write_buf[11] = self.attributes;
        write_buf[12] = 0;
        write_buf[13] = self.creation_time.tenms;
        lsb16!(16, self.creation_time.time);
        lsb16!(18, self.access_time.date);
        lsb16!(20, (((self.first_cluster >> 16) & 0xFFFF) as u16));
        lsb16!(22, self.write_time.time);
        lsb16!(24, self.write_time.date);
        lsb16!(26, ((self.first_cluster & 0xFFFF) as u16));
        lsb16!(28, ((self.file_size & 0xFFFF) as u16));
        lsb16!(30, (((self.file_size >> 16) & 0xFFFF) as u16));
        writer.dentry_write(&write_buf[..]);
    }

    pub fn dentry_read(reader: &mut dyn DentryDataReader) -> Option<Self> {
        let mut read_buf: [u8; DENTRY_SIZE] = [0; DENTRY_SIZE];
        let mut next_id: Option<u8> = None;
        let mut s_chksum: Option<u8> = None;
        let mut lname: [u16; LNAME_MAXLEN] = [0; LNAME_MAXLEN];

        macro_rules! lsb16 {
            ($data_idx: expr) => {
                (read_buf[$data_idx + 1] as u16) << 8 | (read_buf[$data_idx] as u16)
            };

