impl BIOSParameterBlock {
    pub fn new(src: &[u8; 512]) -> Self {
        let mut ret: Self = Self::default();
        ret.load(src);
        ret
    }

    pub fn load(&mut self, src: &[u8; 512]) {
        let mut offset: usize = 0;
        macro_rules! load {
            ($v: expr) => {
                load_fn(&mut $v, src, &mut offset);
            };
        }
        load!(self.basic_bpb._bs_jmp_boot);
        load!(self.basic_bpb._bs_oem_name);

        load!(self.basic_bpb.byts_per_sec);
        load!(self.basic_bpb.sec_per_clus);
        load!(self.basic_bpb.rsvd_sec_cnt);
        load!(self.basic_bpb.num_fats);
        load!(self.basic_bpb.root_ent_cnt);
        load!(self.basic_bpb.tot_sec16);
        load!(self.basic_bpb._media);
        load!(self.basic_bpb.fat_sz16);
        load!(self.basic_bpb._sec_per_trk);
        load!(self.basic_bpb._num_heads);
        load!(self.basic_bpb._hidd_sec);
        load!(self.basic_bpb.tot_sec32);
        load!(self.fat32_bpb.fat_sz32);
        load!(self.fat32_bpb._ext_flags);
        load!(self.fat32_bpb._fs_ver);
        load!(self.fat32_bpb.root_clus);
        load!(self.fat32_bpb.fs_info);
        load!(self.fat32_bpb._bk_boot_sec);
        load!(self.fat32_bpb._reserved);
        load!(self.fat32_bpb._bs_drv_num);
        load!(self.fat32_bpb._bs_reserved1);
        load!(self.fat32_bpb._bs_boot_sig);
        load!(self.fat32_bpb._bs_vol_id);

        load!(self.fat32_bpb._bs_vol_lab);
        load!(self.fat32_bpb._bs_fil_sys_type);
    }
    pub fn validate(&self) -> bool {
        !(self.basic_bpb.byts_per_sec as usize != SECTOR_SIZE
            || self.basic_bpb.root_ent_cnt != 0
            || self.basic_bpb.tot_sec16 != 0
            || self.basic_bpb.fat_sz16 != 0
            || self.fat32_bpb._fs_ver != 0)
    }
}

