type Mutex<T> = SleepLock<T>;

const BLOCKS_PER_PAGE: usize = PAGE_SIZE / BLOCK_SIZE;
pub struct Page {
    pub page_info: Option<Mutex<FilePageInfo>>,
    pub page_permission: SpinLock<MapPermission>,
    pub physical_frame: FrameTracker,
}

pub struct FilePageInfo {
    related_inode: Weak<dyn Inode>,
    start_offset_in_file: usize,
    block_data_states: [DataState; BLOCKS_PER_PAGE],
}

/// Build a page
pub struct PageMaker {
    physical_frame: Option<FrameTracker>,
    page_permission: MapPermission,
    related_inode: Option<Weak<dyn Inode>>,
    is_file_page: bool,
    offset: Option<usize>,
}

impl PageMaker {
    /// Construct a page builder
    pub fn new() -> Self {
        Self {
            offset: None,
            related_inode: None,
            physical_frame: None,
            // TODO: defalut is readable and writable
            page_permission: MapPermission::R | MapPermission::W,
            is_file_page: false,
        }
    }
    /// 设置页面的映射权限。
    ///
    /// # 参数
    ///
    /// * `permission` - 映射权限。
    pub fn permission(mut self, permission: MapPermission) -> Self {
        self.page_permission = permission;
        self
    }
    /// 构建页面。
    pub fn build(mut self) -> Page {
        let frame = match self.physical_frame {
            None => alloc_frame().unwrap(),
            Some(_) => self.physical_frame.take().unwrap(),
        };
        Page {
            page_permission: SpinLock::new(self.page_permission),
            physical_frame: frame,
            page_info: match self.is_file_page {
                true => Some(Mutex::new(FilePageInfo {
                    start_offset_in_file: self.offset.unwrap(),
                    block_data_states: core::array::from_fn(|_| DataState::Stale),
                    related_inode: self.related_inode.unwrap(),
                })),
                false => None,
            },
        }
    }
    /// 设置此页面是否与文件相关。
    #[allow(clippy::wrong_self_convention)]
    pub fn is_file_page(mut self) -> Self {
        self.is_file_page = true;
        self
    }
    /// 设置页面相关的 inode。
    ///
    /// # 参数
    ///
    /// * `inode` - inode 的弱引用。
    pub fn inode(mut self, inode: Weak<dyn Inode>) -> Self {
        self.related_inode = Some(inode);
        self
    }
    /// 设置页面的文件偏移量。
    ///
    /// # 参数
    ///
    /// * `offset` - 文件偏移量。
    pub fn offset(mut self, offset: usize) -> Self {
        self.offset = Some((offset >> PAGE_SIZE_BITS) << PAGE_SIZE_BITS);
        self
    }
}

impl Page {
    /// 同步页面。
    pub async fn sync(&self) -> GeneralResult<()> {
        let file_page_info = self.page_info.as_ref().unwrap().lock().await;
        let inode = file_page_info.related_inode.upgrade().ok_or(Errno::EBADF)?;
        let data_len = inode.metadata().inner.lock().data_len;
        log::trace!(
            "[Page::sync] sync page, file offset {:#x}",
            file_page_info.start_offset_in_file
        );
        for idx in 0..PAGE_SIZE / BLOCK_SIZE {
            match file_page_info.block_data_states[idx] {
                DataState::Dirty => {
                    let page_offset = idx * BLOCK_SIZE;
                    let start_offset_in_file = file_page_info.start_offset_in_file + page_offset;
                    log::trace!(
                        "[Page::sync] sync block of the page, file offset {:#x}",
                        start_offset_in_file
                    );
                    // In case of truncate
                    if data_len <= start_offset_in_file {
                        debug!("[Page::sync] file has been truncated, now len {:#x}, page's file offset {:#x}", data_len, start_offset_in_file);
                        return Ok(());
                    }
                    inode
                        .write(
                            start_offset_in_file,
                            &self.as_bytes_array()[page_offset..page_offset + BLOCK_SIZE],
                        )
                        .await?;
                }
                DataState::Synced => todo!(),
                DataState::Stale => todo!(),
            }
        }
        Ok(())
    }

    /// 写入页面。
    ///
    /// # 参数
    ///
    /// * `offset` - 偏移量。
    /// * `buf` - 要写入的数据。
    pub async fn write(&self, offset: usize, buf: &[u8]) -> GeneralResult<usize> {
        trace!(
            "[Page::write]: page addr {:#x}",
            self as *const Self as usize
        );
        if offset >= PAGE_SIZE {
            Err(Errno::E2BIG)
        } else {
            // let mut inner = self.inner.lock();
            let mut end = offset + buf.len();
