use alloc::{sync::Arc, vec, vec::Vec};
use log::trace;

use crate::{consts::RADIX_TREE_MAP_SHIFT, utils::cell::SyncUnsafeCell};

struct RadixTreeLeafNode<T: Clone> {
    key: usize,
    data: T,
}

struct RadixTreeInternalNode<T: Clone> {
    children: SyncUnsafeCell<[Option<RadixTreeNode<T>>; 2 << RADIX_TREE_MAP_SHIFT]>,
}

impl<T: Clone> RadixTreeInternalNode<T> {
    pub fn new() -> Self {
        Self {
            children: SyncUnsafeCell::new(core::array::from_fn(|_| None)),
        }
    }
}

enum RadixTreeNode<T: Clone> {
    // TODO: not sure use `Box` or `Mutex` or something like that
    InternalNode(Arc<RadixTreeInternalNode<T>>),
    LeafNode(RadixTreeLeafNode<T>),
}

/// To simplify, this struct only fits for those whose Key type is `usize`.
/// All of the mutual exclusion should be guaranteed by user.
#[allow(unused)]
pub struct RadixTree<T: Clone> {
    level_num: usize,
    root: Arc<RadixTreeInternalNode<T>>,
}

// TODO: implement iterator for RadixTree<T>

impl<T: Clone> RadixTree<T> {
    #[allow(unused)]
    pub fn new(level_num: usize) -> Self {
        Self {
            level_num,
            root: Arc::new(RadixTreeInternalNode::new()),
        }
    }
    /// Lookup the give key.
    /// Note that elements that have the same low bits will be put into
    /// the same slot. This is what we want because when this structure
    /// is applied in `PageCache`, we will read pages contiguously.
    #[allow(unused)]
    pub fn lookup(&self, key: usize) -> Option<T> {
        let indice = self.indice(key);
        let mut parent = self.root.clone();
        for index in indice {
            let children = parent.children.get_unchecked_mut();
            if let Some(node) = children[index].as_ref() {
                match node {
                    RadixTreeNode::InternalNode(node) => {
                        let node = node.clone();
                        parent = node;
                    }
                    RadixTreeNode::LeafNode(node) => {
                        if node.key != key {
                            return None;
                        } else {
                            return Some(node.data.clone());
                        }
                    }
                }
            } else {
                return None;
            }
        }
        None
    }

    #[allow(unused)]
    pub fn insert(&mut self, key: usize, value: T) {
        let indice = self.indice(key);
        let mut parent = self.root.clone();
        for (i, index) in indice.iter().enumerate() {
            let children = parent.children.get_unchecked_mut();
            if children[*index].is_none() {
                if i == indice.len() - 1 {
                    trace!("[Radix tree]: insert a new leaf, key: {:#x}", key);
                    children[*index] = Some(RadixTreeNode::LeafNode(RadixTreeLeafNode {
                        key,
                        data: value,
                    }));
                    return;
                }
                children[*index] = Some(RadixTreeNode::InternalNode(Arc::new(
                    RadixTreeInternalNode::new(),
                )));
            }
            let node = children[*index].as_ref().unwrap();
            match node {
                RadixTreeNode::InternalNode(node) => {
                    let node = node.clone();
                    parent = node;
                }
                RadixTreeNode::LeafNode(_) => {
                    trace!(
                        "[Radix tree]: replace old leaf with a new one, key: {:#x}",
                        key
                    );
                    children[*index] = Some(RadixTreeNode::LeafNode(RadixTreeLeafNode {
                        key,
                        data: value,
                    }));
                    return;
                }
            }
        }
    }

    #[allow(unused)]
    fn indice(&self, mut key: usize) -> Vec<usize> {
        let mut indice = vec![0usize; self.level_num];
        for i in (0..self.level_num).rev() {
            indice[i] = key & ((1 << RADIX_TREE_MAP_SHIFT) - 1);
            key >>= RADIX_TREE_MAP_SHIFT;
        }
        indice
    }
}

use alloc::vec;
use alloc::{string::String, vec::Vec};
use log::trace;

#[derive(Eq, Hash, PartialEq, Clone, Debug)]
pub struct HashKey {
    pub parent_ino: usize,
    pub child_name: String,
}

impl HashKey {
    pub fn new(parent_ino: usize, child_name: String) -> Self {
        Self {
            parent_ino,
            child_name,
        }
    }
}
pub trait Hashable {
    fn hash(&self) -> usize;
}

impl Hashable for String {
    // http://www.cse.yorku.ca/~oz/hash.html
    fn hash(&self) -> usize {
        let mut result: usize = 1004535809;
        for c in self.bytes() {
            result = c as usize + (result << 6) + (result << 16) - result;
        }
        result
    }
}

impl Hashable for usize {
    fn hash(&self) -> usize {
        *self
    }
}

#[derive(Clone)]
struct HashCell<Key, Value> {
    key: Key,
    value: Option<Value>,
}

pub struct HashTable<Key, Value> {
    cells: Vec<HashCell<Key, Value>>,
    taken_count: usize,
}

impl<Key, Value> HashTable<Key, Value>
where
    Key: Clone + Default + PartialEq + Hashable,
    Value: Clone,
{
    #[allow(unused)]
    pub fn new() -> Self {
        const INITIAL_CAPACITY: usize = 13;
        let ret = Self {
            // cells: Vec::with_capacity(INITIAL_CAPACITY),
            cells: vec![
                HashCell {
                    key: Key::default(),
                    value: None,
                };
                INITIAL_CAPACITY
            ],
            taken_count: 0,
        };
        trace!("[hash_table] hash table capacity {}", ret.cells.len());
        ret
    }

    #[allow(unused)]
    pub fn extend(&mut self) {
        trace!("[hash_table] enter extend");
        assert!(!self.cells.is_empty());
        let mut new_self = Self {
            cells: vec![
                HashCell {
                    key: Key::default(),
                    value: None,
                };
                self.cells.len() * 2 + 1
            ],
            taken_count: 0,
        };

        trace!("extend capacity to {}", new_self.cells.len());

        for cell in self.cells.iter() {
            if cell.value.is_some() {
                new_self.insert(cell.key.clone(), cell.value.clone().unwrap());
            }
        }

        *self = new_self;
    }

    #[allow(unused)]
    pub fn insert(&mut self, key: Key, new_value: Value) {
        trace!("[hash_table] enter insert");
        if let Some(old_value) = self.get_mut(&key) {
            *old_value = new_value;
        } else {
            if self.taken_count >= self.cells.len() {
                self.extend();
            }
            assert!(self.taken_count < self.cells.len());

            let mut index = key.hash() % self.cells.len();

            trace!("index: {}", index);

            while self.cells[index].value.is_some() {
                index = (index + 1) % self.cells.len();
            }

            self.cells[index].key = key;
            self.cells[index].value = Some(new_value);
            self.taken_count += 1;
        }
        trace!("[hash_table] leave insert");
    }

    #[allow(unused)]
    pub fn delete(&mut self, key: Key) {
        trace!("[hash_table] enter delete, key: {}", key.hash());
        if let Some(index) = self.get_index(&key) {
            self.cells[index].value.take();
        }
    }

    fn get_index(&self, key: &Key) -> Option<usize> {
        trace!(
            "[hash_table] enter get_index key:{}, len:{}",
            key.hash(),
            self.cells.len()
        );
        let mut index = key.hash() % self.cells.len();
        for _ in 0..self.cells.len() {
            if self.cells[index].value.is_none() {
                break;
            }

            if self.cells[index].key == *key {
                break;
            }

            index = (index + 1) % self.cells.len();
        }

        if self.cells[index].value.is_some() && self.cells[index].key == *key {
            Some(index)
        } else {
            None
        }
    }

    #[allow(dead_code)]
    pub fn get(&self, key: &Key) -> Option<&Value> {
        trace!("[hash_table] enter get key: {}", key.hash());
        if let Some(index) = self.get_index(key) {
            self.cells[index].value.as_ref()
            // Some(&self.cells[index].value)
        } else {
            None
        }
    }

    pub fn get_mut(&mut self, key: &Key) -> Option<&mut Value> {
        trace!("[hash_table] enter get_mut key: {}", key.hash());
        if let Some(index) = self.get_index(key) {
            self.cells[index].value.as_mut()
            // Some(&mut self.cells[index].value)
        } else {
            None
        }
    }
}
